parameters.jsCode:
const searchResult = $input.first().json;
const original = $('Limpiar Query').first().json;

let pmids = [];
if (searchResult.esearchresult && searchResult.esearchresult.idlist) {
  pmids = searchResult.esearchresult.idlist;
}

if (pmids.length === 0) {
  return [{
    json: { ...original, no_results: true, analysis: 'No se encontraron artículos científicos relevantes.' }
  }];
}

return [{
  json: { ...original, pmids: pmids, pmid_list: pmids.join(','), article_count: pmids.length }
}];

