parameters.jsCode:
const geminiOutput = $input.first().json;

const articles =
  $('Directionality Engine').first().json.articles ||
  $('Build AI Evidence Context').first().json.articles ||
  $input.first().json.articles ||
  [];

const original = $('Normalizar Claim').first().json;

const lang = original.language || 'es';
const isEn = lang === 'en';

const labels = isEn
  ? {
      claimUnavailable: 'Claim unavailable',
      analyzedClaim: 'Analyzed claim',
      shortClaim: 'Claim',
      verdict: 'Verdict',
      confidence: 'Confidence',
      consensus: 'Scientific consensus',
      shortConsensus: 'Consensus',
      summary: 'Summary',
      detailedAnalysis: 'Detailed analysis',
      shortAnalysis: 'Brief analysis',
      strengths: 'Methodological strengths',
      limitations: 'Limitations',
      keyLimitations: 'Key limitations',
      biases: 'Potential biases / conflicts',
      keyCitations: 'Key citations',
      pubmedReferences: 'PubMed references',
      mainReferences: 'Main references',
      disclaimer: 'AI-generated analysis based on PubMed-indexed articles. It does not replace professional clinical judgment.',
      fullDisclaimer: 'AI-generated analysis based on PubMed-indexed articles. It does not replace professional clinical judgment. Always verify the original sources.',
      articlesAnalyzed: 'Articles analyzed',
      date: 'Date',
      parseError: 'Gemini returned an invalid format',
      parseErrorLimit: 'The AI response could not be parsed correctly',
      processingError: 'Error processing the analysis',
      technicalError: 'A technical error occurred while analyzing the evidence.',
      notDetermined: 'Not determined',
      couldNotDetermine: 'Could not be determined',
    }
  : {
      claimUnavailable: 'Claim no disponible',
      analyzedClaim: 'Afirmación analizada',
      shortClaim: 'Afirmación',
      verdict: 'Veredicto',
      confidence: 'Confianza',
      consensus: 'Consenso científico',
      shortConsensus: 'Consenso',
      summary: 'Resumen',
      detailedAnalysis: 'Análisis detallado',
      shortAnalysis: 'Análisis breve',
      strengths: 'Fortalezas metodológicas',
      limitations: 'Limitaciones',
      keyLimitations: 'Limitaciones clave',
      biases: 'Posibles sesgos / conflictos',
      keyCitations: 'Citas clave',
      pubmedReferences: 'Referencias PubMed',
      mainReferences: 'Referencias principales',
      disclaimer: 'Análisis generado por IA a partir de artículos indexados en PubMed. No sustituye juicio clínico profesional.',
      fullDisclaimer: 'Análisis generado por IA a partir de artículos indexados en PubMed. No sustituye juicio clínico profesional. Verifica siempre las fuentes originales.',
      articlesAnalyzed: 'Artículos analizados',
      date: 'Fecha',
      parseError: 'Gemini devolvió un formato inválido',
      parseErrorLimit: 'La respuesta IA no pudo parsearse correctamente',
      processingError: 'Error al procesar el análisis',
      technicalError: 'Hubo un error técnico al analizar la evidencia.',
      notDetermined: 'No determinado',
      couldNotDetermine: 'No se pudo determinar',
    };

function displayVerdict(value) {
  const map = {
    VERDADERO: isEn ? 'TRUE' : 'VERDADERO',
    PARCIALMENTE_CIERTO: isEn ? 'PARTIAL' : 'PARCIALMENTE CIERTO',
    EXAGERADO: isEn ? 'EXAGGERATED' : 'EXAGERADO',
    FALSO: isEn ? 'FALSE' : 'FALSO',
    EVIDENCIA_INSUFICIENTE: isEn ? 'INSUFFICIENT EVIDENCE' : 'EVIDENCIA INSUFICIENTE',

    TRUE: isEn ? 'TRUE' : 'VERDADERO',
    PARTIALLY_TRUE: isEn ? 'PARTIAL' : 'PARCIALMENTE CIERTO',
    EXAGGERATED: isEn ? 'EXAGGERATED' : 'EXAGERADO',
    FALSE: isEn ? 'FALSE' : 'FALSO',
    INSUFFICIENT_EVIDENCE: isEn ? 'INSUFFICIENT EVIDENCE' : 'EVIDENCIA INSUFICIENTE',

    ERROR_ANALISIS: isEn ? 'ANALYSIS ERROR' : 'ERROR DE ANÁLISIS',
  };

  return map[value] || value || 'UNKNOWN';
}

function displayConsensus(value) {
  const map = {
    FUERTE: isEn ? 'STRONG' : 'FUERTE',
    MODERADO: isEn ? 'MODERATE' : 'MODERADO',
    DÉBIL: isEn ? 'WEAK' : 'DÉBIL',
    DEBIL: isEn ? 'WEAK' : 'DÉBIL',
    MIXTO: isEn ? 'MIXED' : 'MIXTO',
    INSUFICIENTE: isEn ? 'INSUFFICIENT' : 'INSUFICIENTE',

    STRONG: isEn ? 'STRONG' : 'FUERTE',
    MODERATE: isEn ? 'MODERATE' : 'MODERADO',
    WEAK: isEn ? 'WEAK' : 'DÉBIL',
    MIXED: isEn ? 'MIXED' : 'MIXTO',
    INSUFFICIENT: isEn ? 'INSUFFICIENT' : 'INSUFICIENTE',
    UNCLEAR: isEn ? 'UNCLEAR' : 'NO CLARO',
  };

  return map[value] || value || 'UNKNOWN';
}

let analysis = {};

try {
  const text = geminiOutput.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const clean = text.replace(/```json/gi, '').replace(/```/g, '').trim();
  const match = clean.match(/\{[\s\S]*\}/);

  try {
    analysis = JSON.parse(match ? match[0] : clean);
  } catch (innerError) {
    const repaired = clean
      .replace(/,\s*}/g, '}')
      .replace(/,\s*]/g, ']')
      .replace(/\n/g, ' ')
      .trim();

    try {
      analysis = JSON.parse(repaired);
    } catch (repairError) {
      analysis = {
        veredicto: 'ERROR_ANALISIS',
        explicacion_corta: labels.parseError,
        analisis_detallado: clean.slice(0, 2000),
        fortalezas: [],
        limitaciones: [labels.parseErrorLimit],
        conflictos_potenciales: labels.notDetermined,
        citas_clave: [],
        confidence_level: 'LOW',
        consensus_level: 'UNCLEAR'
      };
    }
  }
} catch (e) {
  analysis = {
    veredicto: 'ERROR_ANALISIS',
    explicacion_corta: labels.processingError,
    analisis_detallado: labels.technicalError,
    fortalezas: [],
    limitaciones: [],
    conflictos_potenciales: labels.couldNotDetermine,
    citas_clave: [],
    confidence_level: 'LOW',
    consensus_level: 'UNCLEAR'
  };
}

const emoji = {
  VERDADERO: '✅',
  TRUE: '✅',

  PARCIALMENTE_CIERTO: '⚠️',
  PARTIALLY_TRUE: '⚠️',

  EXAGERADO: '⚠️',
  EXAGGERATED: '⚠️',

  FALSO: '❌',
  FALSE: '❌',

  EVIDENCIA_INSUFICIENTE: '❓',
  INSUFFICIENT_EVIDENCE: '❓',

  ERROR_ANALISIS: '⚠️'
};

const originalClaimSafe =
  original.original_claim ||
  original.claim ||
  $json.original_claim ||
  $json.claim ||
  labels.claimUnavailable;

const verdictLabel = displayVerdict(analysis.veredicto);
const consensusLabel = displayConsensus(analysis.consensus_level);

// ============================================
// WHATSAPP — bilingual ES/EN
// ============================================

let mensaje = `${emoji[analysis.veredicto] || '🔍'} *EVIDENCE CHECK*\n`;
mensaje += `━━━━━━━━━━━━━━━━━━━━\n\n`;
mensaje += `📌 *${labels.analyzedClaim}:*\n${originalClaimSafe}\n\n`;
mensaje += `🎯 *${labels.verdict}:* ${verdictLabel}\n`;
mensaje += `📊 *${labels.confidence}:* ${analysis.confidence_level || 'UNKNOWN'}\n`;
mensaje += `🧠 *${labels.consensus}:* ${consensusLabel}\n\n`;
mensaje += `📝 *${labels.summary}:* ${analysis.explicacion_corta || ''}\n\n`;
mensaje += `📊 *${labels.detailedAnalysis}:*\n${analysis.analisis_detallado || ''}\n\n`;

if (analysis.fortalezas?.length) {
  mensaje += `✅ *${labels.strengths}:*\n`;
  analysis.fortalezas.forEach(f => mensaje += `• ${f}\n`);
  mensaje += `\n`;
}

if (analysis.limitaciones?.length) {
  mensaje += `⚠️ *${labels.limitations}:*\n`;
  analysis.limitaciones.forEach(l => mensaje += `• ${l}\n`);
  mensaje += `\n`;
}

mensaje += `🔍 *${labels.biases}:*\n${analysis.conflictos_potenciales || labels.notDetermined}\n\n`;
mensaje += `📚 *${labels.pubmedReferences}:*\n`;

articles.slice(0, 5).forEach((article, idx) => {
  mensaje += `${idx + 1}. ${article.title}\n`;
  mensaje += `${article.journal} (${article.pubdate}) | PMID: ${article.pmid}\n`;
  mensaje += `${article.url}\n\n`;
});

mensaje += `⚠️ *${labels.disclaimer.split('.')[0]}:*\n`;
mensaje += `${labels.disclaimer}\n\n`;
mensaje += `🔬 ${labels.articlesAnalyzed}: ${articles.length}\n`;
mensaje += `📅 ${labels.date}: ${new Date().toISOString().split('T')[0]}`;

// ============================================
// EMAIL — bilingual ES/EN
// ============================================

const emailHtml = `
<h2>EvidenceCheck AI</h2>

<h3>${labels.analyzedClaim}</h3>
<p>${originalClaimSafe}</p>

<h3>${labels.verdict}</h3>
<p><strong>${verdictLabel}</strong></p>

<h3>${labels.confidence}</h3>
<p>${analysis.confidence_level || 'UNKNOWN'}</p>

<h3>${labels.consensus}</h3>
<p>${consensusLabel}</p>

<h3>${labels.summary}</h3>
<p>${analysis.explicacion_corta || ''}</p>

<h3>${labels.detailedAnalysis}</h3>
<p>${analysis.analisis_detallado || ''}</p>

<h3>${labels.strengths}</h3>
<ul>
${(analysis.fortalezas || []).map(f => `<li>${f}</li>`).join('')}
</ul>

<h3>${labels.limitations}</h3>
<ul>
${(analysis.limitaciones || []).map(l => `<li>${l}</li>`).join('')}
</ul>

<h3>${labels.biases}</h3>
<p>${analysis.conflictos_potenciales || labels.notDetermined}</p>

<h3>${labels.keyCitations}</h3>
<ul>
${(analysis.citas_clave || []).map(c => `<li>${c}</li>`).join('')}
</ul>

<h3>${labels.pubmedReferences}</h3>
<ol>
${articles.map(a => `
<li>
<strong>${a.title}</strong><br>
${a.authors || ''}<br>
<em>${a.journal}</em> (${a.pubdate})<br>
PMID: ${a.pmid}<br>
<a href="${a.url}">${a.url}</a>
</li>
`).join('')}
</ol>

<hr>

<p><strong>${labels.disclaimer}:</strong> ${labels.fullDisclaimer}</p>

<p><strong>${labels.date}:</strong> ${new Date().toISOString().split('T')[0]}</p>
`;

const MAX_WHATSAPP = 3900;

if (mensaje.length > MAX_WHATSAPP) {
  const refs = articles.slice(0, 3).map((article, idx) =>
    `${idx + 1}. ${article.title}\nPMID: ${article.pmid}\n${article.url}`
  ).join('\n\n');

  mensaje = `${emoji[analysis.veredicto] || '🔍'} *EVIDENCE CHECK*\n`;
  mensaje += `━━━━━━━━━━━━━━━━━━━━\n\n`;
  mensaje += `📌 *${labels.shortClaim}:*\n${originalClaimSafe}\n\n`;
  mensaje += `🎯 *${labels.verdict}:* ${verdictLabel}\n`;
  mensaje += `📊 *${labels.confidence}:* ${analysis.confidence_level || 'UNKNOWN'}\n`;
  mensaje += `🧠 *${labels.shortConsensus}:* ${consensusLabel}\n\n`;
  mensaje += `📝 *${labels.summary}:* ${analysis.explicacion_corta || ''}\n\n`;
  mensaje += `📊 *${labels.shortAnalysis}:*\n${String(analysis.analisis_detallado || '').slice(0, 1200)}...\n\n`;

  if (analysis.limitaciones?.length) {
    mensaje += `⚠️ *${labels.keyLimitations}:*\n`;
    analysis.limitaciones.slice(0, 3).forEach(l => mensaje += `• ${l}\n`);
    mensaje += `\n`;
  }

  mensaje += `📚 *${labels.mainReferences}:*\n${refs}\n\n`;
  mensaje += `⚠️ ${labels.disclaimer}\n`;
  mensaje += `🔬 ${labels.articlesAnalyzed}: ${articles.length}`;
}

if (
  analysis.consensus_level === 'MIXED' &&
  analysis.evidence_consensus_assessment?.overall_consensus === 'WEAK'
) {
  analysis.evidence_consensus_assessment.overall_consensus = 'MIXED';
}

if (
  analysis.consensus_level === 'STRONG' &&
  analysis.evidence_consensus_assessment?.overall_consensus === 'WEAK'
) {
  analysis.evidence_consensus_assessment.overall_consensus = 'STRONG';
}

if (
  analysis.consensus_level === 'MODERATE' &&
  analysis.evidence_consensus_assessment?.overall_consensus === 'WEAK'
) {
  analysis.evidence_consensus_assessment.overall_consensus = 'MODERATE';
}

// ============================================
// VALIDAR Y LIMPIAR NÚMERO DE TELÉFONO
// ============================================

function getValidWhatsAppNumber(phone) {
  const invalidValues = ['unknown', '', null, undefined, '=', '#', 'default', 'undefined', 'null', '0', '-1'];
  const phoneStr = String(phone || '').trim();

  if (invalidValues.includes(phoneStr)) {
    return null;
  }

  const digitsOnly = phoneStr.replace(/\D/g, '');
  if (digitsOnly.length < 8) {
    return null;
  }

  return digitsOnly;
}

let whatsappNumber = getValidWhatsAppNumber(original.from);

if (!whatsappNumber) {
  whatsappNumber = $env.DEFAULT_WHATSAPP_TO || 'unknown';
}

return [{
  json: {
    ...original,
    ...analysis,
    articles,

    actual_verdict: analysis.veredicto || null,
    actual_confidence: analysis.confidence_level || null,
    actual_consensus: analysis.consensus_level || null,
    actual_reasoning: analysis.analisis_detallado || '',

    whatsappText: mensaje,
    whatsappTo: whatsappNumber,

    emailSubject: `EvidenceCheck AI - ${verdictLabel} - ${originalClaimSafe.slice(0, 60)}`,

    emailHtml
  }
}];

const input = $input.first().json;

const claimText = String(
  input.claim_limpio ||
  input.original_claim ||
  input.claim ||
  ''
).toLowerCase();

const articles = (input.articles || []).map(article => {
  const title = String(article.title || '').toLowerCase();
  const abstract = String(article.abstract || '').toLowerCase();
  const mesh = (article.mesh_terms || []).join(' ').toLowerCase();
  const pubTypes = (article.publication_types || []).join(' ').toLowerCase();

  const fullText = `${title} ${abstract} ${mesh} ${pubTypes}`;

  let study_type = 'UNKNOWN';

  if (title.includes('umbrella review') || abstract.includes('umbrella review')) {
    study_type = 'UMBRELLA_REVIEW';
  } else if (
    (title.includes('systematic review') || abstract.includes('systematic review')) &&
    (title.includes('meta-analysis') || abstract.includes('meta-analysis'))
  ) {
    study_type = 'SYSTEMATIC_REVIEW_META_ANALYSIS';
  } else if (title.includes('meta-analysis') || abstract.includes('meta-analysis') || pubTypes.includes('meta-analysis')) {
    study_type = 'META_ANALYSIS';
  } else if (
    title.includes('randomized') ||
    title.includes('randomised') ||
    title.includes('clinical trial') ||
    pubTypes.includes('randomized controlled trial') ||
    pubTypes.includes('clinical trial')
  ) {
    study_type = 'RCT_OR_CLINICAL_TRIAL';
  } else if (
    title.includes('prospective') ||
    title.includes('cohort') ||
    abstract.includes('prospective cohort') ||
    mesh.includes('prospective studies') ||
    mesh.includes('cohort studies')
  ) {
    study_type = 'OBSERVATIONAL_COHORT';
  } else if (title.includes('case-control') || abstract.includes('case-control') || mesh.includes('case-control studies')) {
    study_type = 'CASE_CONTROL';
  } else if (title.includes('cross-sectional') || abstract.includes('cross-sectional') || mesh.includes('cross-sectional studies')) {
    study_type = 'CROSS_SECTIONAL';
  }

  // 1. Exposure specificity penalty
  let exposure_specificity_penalty = 0;
  const exposure_confusion_flags = [];

  const confusionPairs = [
    {
      claim: /sugar|azucar|azúcar|sucrose|fructose|dietary sugar|added sugar/,
      falseMatch: /artificial sweetener|non-sugar sweetener|non sugar sweetener|non-nutritive sweetener|aspartame|saccharin|sucralose|stevia|acesulfame/,
      reason: 'Claim habla de azúcar, pero el artículo trata principalmente de edulcorantes artificiales.'
    },
    {
      claim: /red meat|carne roja/,
      falseMatch: /processed meat|cold cuts|sausage|bacon|ham|embutido/,
      reason: 'Claim habla de carne roja, pero el artículo trata principalmente de carne procesada.'
    },
    {
      claim: /sun exposure|uv|radiacion uv|radiación uv|ultraviolet/,
      falseMatch: /phototherapy|uv lamp|tanning bed/,
      reason: 'Claim habla de exposición solar/UV general, pero el artículo trata de una fuente o uso específico de UV.'
    },
    {
      claim: /alcohol|alcohol consumption|bebidas alcoholicas|bebidas alcohólicas/,
      falseMatch: /hand sanitizer|rubbing alcohol|alcohol-based/,
      reason: 'Claim habla de consumo de alcohol, pero el artículo trata de alcohol no ingerido.'
    }
  ];

  for (const pair of confusionPairs) {
    if (pair.claim.test(claimText) && pair.falseMatch.test(fullText)) {
      exposure_specificity_penalty -= 35;
      exposure_confusion_flags.push(pair.reason);
    }
  }

  // 2. Claim centrality score
  let claim_centrality_score = 0;
  const centrality_reasons = [];

  const firstSentence = abstract.split(/[.!?]/)[0] || '';
  const firstAbstractBlock = abstract.slice(0, 500);

  const exposureTerms = [];

  if (/sugar|azucar|azúcar|sucrose|fructose/.test(claimText)) {
    exposureTerms.push('sugar', 'dietary sugar', 'added sugar', 'sucrose', 'fructose', 'sugar-sweetened');
  }

  if (/cancer|cáncer|tumor|neoplasm|carcinoma/.test(claimText)) {
    exposureTerms.push('cancer', 'neoplasms', 'tumor', 'carcinoma');
  }

  if (/smoking|fumar|tabaco|tobacco/.test(claimText)) {
    exposureTerms.push('smoking', 'tobacco', 'cigarette');
  }

  if (/uv|ultraviolet|radiacion uv|radiación uv/.test(claimText)) {
    exposureTerms.push('ultraviolet', 'uv radiation', 'sun exposure', 'skin cancer', 'melanoma');
  }

  const uniqueTerms = [...new Set(exposureTerms)];

  const titleMatches = uniqueTerms.filter(t => title.includes(t));
  const firstSentenceMatches = uniqueTerms.filter(t => firstSentence.includes(t));
  const meshMatches = uniqueTerms.filter(t => mesh.includes(t));
  const abstractMatches = uniqueTerms.filter(t => abstract.includes(t));

  if (titleMatches.length >= 2) {
    claim_centrality_score += 25;
    centrality_reasons.push('Varios términos centrales aparecen en el título.');
  } else if (titleMatches.length === 1) {
    claim_centrality_score += 12;
    centrality_reasons.push('Un término central aparece en el título.');
  }

  if (firstSentenceMatches.length >= 2) {
    claim_centrality_score += 15;
    centrality_reasons.push('El claim aparece como tema central al inicio del abstract.');
  }

  if (meshMatches.length >= 2) {
    claim_centrality_score += 15;
    centrality_reasons.push('Los términos centrales aparecen en MeSH.');
  }

  if (abstractMatches.length >= 2 && titleMatches.length === 0) {
    claim_centrality_score += 5;
    centrality_reasons.push('Los términos aparecen en el abstract, pero no en el título.');
  }

  // 3. Outcome tier weighting
  let outcome_tier_score = 0;
  let outcome_tier = 'UNKNOWN';

  const tier1 = /cancer incidence|incidence of .*cancer|liver cancer|breast cancer|colorectal cancer|pancreatic cancer|lung cancer|mortality|death|cardiovascular event|myocardial infarction|stroke/;
  const tier2 = /hospitalization|disease progression|recurrence|chronic disease mortality/;
  const tier3 = /biomarker|surrogate|blood pressure|cholesterol|glucose|insulin|inflammatory marker/;
  const tier4 = /in vitro|cell line|animal model|mice|mouse|rat|murine/;

  if (tier1.test(fullText)) {
    outcome_tier = 'TIER_1_HARD_OUTCOME';
    outcome_tier_score += 20;
  } else if (tier2.test(fullText)) {
    outcome_tier = 'TIER_2_CLINICAL_OUTCOME';
    outcome_tier_score += 10;
  } else if (tier3.test(fullText)) {
    outcome_tier = 'TIER_3_SURROGATE_OUTCOME';
    outcome_tier_score += 0;
  } else if (tier4.test(fullText)) {
    outcome_tier = 'TIER_4_PRECLINICAL_OR_INDIRECT';
    outcome_tier_score -= 15;
  }

  return {
    ...article,
    study_type,
    relevance_modifiers: {
      exposure_specificity_penalty,
      exposure_confusion_flags,
      claim_centrality_score,
      centrality_reasons,
      outcome_tier,
      outcome_tier_score
    }
  };
});

return [{
  json: {
    ...input,
    articles
  }
}];

const original = $input.first().json;
const dc = original.claim_decomposition || {};

const exposure = dc.exposure || 'unknown exposure';
const exposureTerms = dc.exposure_terms || original.keywords_extraidas || [];

const outcome = dc.outcome || 'general health outcome';
const outcomeTerms = dc.outcome_terms || original.keywords_extraidas || [];

const population = dc.population || 'general population';
const relationshipType = dc.relationship_type || 'association';
const causalLanguage = dc.causal_language || false;
const claimStrength = dc.claim_strength || 'moderate';
const claimDirection = dc.claim_direction || 'unclear';
const fallbackTerms = original.search_query_fallback || '';

return [{
  json: {
    ...original,
    geminiQueryPrompt: `
Convierte el siguiente claim médico/nutricional en una query optimizada para PubMed.

OBJETIVO:
Crear una query que capture la relación científica principal:
EXPOSICIÓN / INTERVENCIÓN + OUTCOME / ENFERMEDAD + DISEÑO DE ESTUDIO.

=== CLAIM ORIGINAL ===
"${original.original_claim}"

=== CLAIM DESCOMPUESTO ===
Exposición principal: ${exposure}
Términos de exposición: ${JSON.stringify(exposureTerms)}
Outcome principal: ${outcome}
Términos de outcome: ${JSON.stringify(outcomeTerms)}
Población: ${population}
Tipo de relación: ${relationshipType}
Lenguaje causal: ${causalLanguage}
Fuerza del claim: ${claimStrength}
Dirección del claim: ${claimDirection}

=== QUERY FALLBACK DISPONIBLE ===
${fallbackTerms}

Úsala solo como referencia si la descomposición del claim es incompleta.

REGLAS GENERALES:
- Solo devuelve la query.
- Usa términos médicos en inglés.
- No expliques nada.
- No uses markdown.
- No devuelvas JSON.
- Usa OR para sinónimos.
- Usa AND para conceptos principales.
- La query debe exigir que aparezcan tanto la exposición como el outcome.
- Evita términos vagos como "health benefits".
- Evita términos demasiado genéricos como "risk", "death" o "survival" si no van acompañados de contexto clínico específico.
- No incluyas palabras en español.
- Prioriza términos MeSH y expresiones habituales de PubMed.
- No hagas queries de dieta general si el claim habla de un nutriente concreto.
- No metas outcomes cardiovasculares si el claim habla de cáncer, salvo que el claim lo mencione.
