  if (titleHasOutcome) relevance_score += 12;
  if (titleHasExposure && titleHasOutcome) relevance_score += 25;

  if (strongExposureTitleMatch) relevance_score += 35;

  relevance_score += Math.min(article.evidence_weight || 0, 18);

  if (article.is_human_evidence) relevance_score += 4;

  if (article.has_hard_outcomes) {
    relevance_score += wantsMortality || wantsCardio || wantsCancer ? 8 : 4;
  }

  if (article.has_surrogate_outcomes) {
    relevance_score += wantsCardio || wantsDiabetes || wantsWeight ? 3 : 0;
  }

  const design = String(article.study_design || '').toUpperCase();

  if (design.includes('SYSTEMATIC_REVIEW_META_ANALYSIS')) relevance_score += 10;
  else if (design.includes('META_ANALYSIS')) relevance_score += 9;
  else if (design.includes('SYSTEMATIC_REVIEW')) relevance_score += 8;
  else if (design.includes('RCT')) relevance_score += wantsTreatment || wantsSupplement ? 10 : 6;
  else if (design.includes('COHORT')) relevance_score += wantsMortality || wantsCancer ? 6 : 3;

  conditionalPopulations.forEach(p => {
    if (!p.allowed && fullText.includes(p.term)) relevance_score -= 10;
  });

  const indirectTopics = [
    'gut microbiota',
    'ultra-processed',
    'fatty liver',
    'metabolomics',
    'genetic polymorphism',
    'in vitro'
  ];

  indirectTopics.forEach(term => {
    if (!claimText.includes(term) && fullText.includes(term)) relevance_score -= 8;
  });

  if (matched_terms.length === 0 && matched_outcomes.length === 0) {
    relevance_score -= 15;
  }

  if (hasExposure && hasOutcome) {
    relevance_score += 25;
  } else if (hasExposure && !hasOutcome) {
    relevance_score -= 28;
  } else if (!hasExposure && hasOutcome) {
    relevance_score -= 60;
  } else {
    relevance_score -= 30;
  }

  if (hasExposure && !titleHasExposure) relevance_score -= 20;
  if (hasOutcome && !titleHasOutcome) relevance_score -= 10;

  if (hasExposure && hasOutcome && !strongExposureTitleMatch) {
    relevance_score -= 35;
  }

  if (strongRelationMatch) {
    relevance_score += 35;
  }

  if (hasExposure && hasOutcome && !strongRelationMatch) {
    relevance_score -= 20;
  }

  if (!hasExposure && hasOutcome) {
    relevance_score -= 30;
  }

article.canonical = article.canonical || {};

article.canonical.relevance = {
  score: relevance_score,
  has_exposure: hasExposure,
  has_outcome: hasOutcome,
  strong_relation_match: strongRelationMatch
};

  return {
    ...article,
    relevance_score,
    matched_terms: [...new Set(matched_terms)],
    matched_outcomes: [...new Set(matched_outcomes)],
    matched_exposure: [...new Set(matched_exposure)],
    canonical_exposure_overlap: canonicalExposureOverlap,
    title_exposure_matches: [...new Set(titleExposureMatches)],
    title_outcome_matches: [...new Set(titleOutcomeMatches)],
    has_exposure: hasExposure,
    has_outcome: hasOutcome,
    title_has_exposure: titleHasExposure,
    title_has_outcome: titleHasOutcome,
    strong_exposure_title_match: strongExposureTitleMatch,
    title_relation_match: titleRelationMatch,
    abstract_relation_match: abstractRelationMatch,
    sentence_relation_match: sentenceRelationMatch,
    strong_relation_match: strongRelationMatch,
    debug_sentence_matches: debugMatches,
    underlying_evidence_type,
causal_inference_strength:
  underlying_evidence_type === 'INTERVENTIONAL'
    ? 'MODERATE_TO_HIGH'
    : underlying_evidence_type === 'OBSERVATIONAL_META_ANALYSIS'
    ? 'LOW_TO_MODERATE'
    : underlying_evidence_type === 'OBSERVATIONAL_REVIEW'
    ? 'LOW_TO_MODERATE'
    : underlying_evidence_type === 'OBSERVATIONAL'
    ? 'LOW'
    : underlying_evidence_type === 'PRECLINICAL'
    ? 'VERY_LOW'
    : 'UNCLEAR'
  };
});

const sortedScored = scored
  .sort((a, b) => b.relevance_score - a.relevance_score);

const filtered = sortedScored
  .filter(a =>
    a.has_exposure === true &&
    a.has_outcome === true &&
    a.semantic_claim_match_score > 0
  )
  .slice(0, 6);

const selectedArticles = filtered;

const coverageArticles = selectedArticles;

const strongMatchCount = coverageArticles.filter(a => a.strong_relation_match).length;
const exposureMatchCount = coverageArticles.filter(a => a.has_exposure).length;
const outcomeMatchCount = coverageArticles.filter(a => a.has_outcome).length;

const avgRelevanceScore = coverageArticles.length
  ? coverageArticles.reduce((sum, a) => sum + Number(a.relevance_score || 0), 0) / coverageArticles.length
  : 0;

let coverageQuality = 'INSUFFICIENT';

if (strongMatchCount >= 2 && avgRelevanceScore >= 80) {
  coverageQuality = 'HIGH';
} else if (strongMatchCount >= 1 && avgRelevanceScore >= 40) {
  coverageQuality = 'MODERATE';
} else if (exposureMatchCount > 0 && outcomeMatchCount > 0) {
  coverageQuality = 'LOW';
}

return [{
  json: {
    ...input,

    articles: selectedArticles,
    all_ranked_articles: sortedScored,

    filtered_article_count: selectedArticles.length,

    retrieval_coverage: {
      coverage_quality: coverageQuality,
      avg_relevance_score: avgRelevanceScore,
      strong_match_count: strongMatchCount,
      exposure_match_count: exposureMatchCount,
      outcome_match_count: outcomeMatchCount,
      has_systematic_review: coverageArticles.some(a =>
        String(a.study_type || '').includes('SYSTEMATIC_REVIEW') ||
        String(a.study_type || '').includes('META_ANALYSIS') ||
        String(a.study_type || '').includes('UMBRELLA_REVIEW')
      ),
      has_recent_evidence: coverageArticles.some(a => Number(a.publication_year || 0) >= 2020),
      outcome_coverage: [...new Set(coverageArticles.map(a => a.canonical?.outcome_category).filter(Boolean))],
      exposure_coverage: [...new Set(coverageArticles.flatMap(a => a.matched_exposure || []))],
      missing_dimensions: [
        ...(exposureMatchCount === 0 ? ['EXPOSURE_NOT_CLEARLY_COVERED'] : []),
        ...(outcomeMatchCount === 0 ? ['OUTCOME_NOT_CLEARLY_COVERED'] : []),
        ...(strongMatchCount === 0 ? ['NO_STRONG_EXPOSURE_OUTCOME_MATCH'] : [])
      ],
      possible_query_bias: coverageQuality === 'INSUFFICIENT',
      retrieval_confidence:
        coverageQuality === 'HIGH' ? 'HIGH' :
        coverageQuality === 'MODERATE' ? 'MODERATE' : 'LOW',
      articles_considered: coverageArticles.length,
      gemini_instruction:
        coverageQuality === 'INSUFFICIENT'
          ? 'La recuperación de evidencia parece insuficiente: baja la confianza y evita conclusiones fuertes.'
          : ''
    },

    scoring_context: {
      claim_type: claimType,
      claim_problem: claimProblem,
      detected_outcomes: targetOutcomes,
      detected_terms: uniqueTerms,
      detected_exposures: exposureTerms
    }
  }
}];

// ============================================
// PROCESAR ABSTRACTS - VERSIÓN CORREGIDA
// Extrae XML real de PubMed, parsea abstracts,
// publication types y MeSH terms
// ============================================

const input = $input.first().json;

const original =
  $('Construir Artículos Completos').first().json ||
  $('Parsear PMIDs').first().json ||
  {};

// ============================================
// 1. RECUPERAR ARTÍCULOS BASE
// ============================================

let articles =
  input.articles ||
  $('Construir Artículos Completos').first().json.articles ||
  [];

if (!articles.length) {
  throw new Error('No se encontraron artículos base para procesar abstracts');
}

// ============================================
// 2. RECUPERAR XML REAL
// ============================================

const pubmedXmlInput =
  $input.first().json?.data ||
  $input.first().json?.body ||
  $input.first().json?.response ||
  $input.first().json?.text ||
  $input.first().json?.xml ||
  $('PubMed: Obtener Abstracts').first().json?.data ||
  $('PubMed: Obtener Abstracts').first().json?.body ||
  $('PubMed: Obtener Abstracts').first().json?.response ||
  $('PubMed: Obtener Abstracts').first().json?.text ||
  $('PubMed: Obtener Abstracts').first().json?.xml;

if (typeof pubmedXmlInput !== 'string') {
  throw new Error(
    'No se encontró XML string válido. Revisa que PubMed: Obtener Abstracts devuelve data con XML.'
  );
}

let xmlText = pubmedXmlInput
  .replace(/\\"/g, '"')
  .replace(/\\n/g, '\n')
  .replace(/\\t/g, '\t')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&amp;/g, '&');

// ============================================
// 3. EXTRAER BLOQUES PUBMEDARTICLE
// ============================================

let pubmedArticles =
  xmlText.match(/<PubmedArticle\b[^>]*>[\s\S]*?<\/PubmedArticle>/gi) || [];

if (pubmedArticles.length === 0) {
  pubmedArticles =
    xmlText.match(/<pubmedarticle\b[^>]*>[\s\S]*?<\/pubmedarticle>/gi) || [];
}

if (pubmedArticles.length === 0 && xmlText.includes('<?xml')) {
  const xmlMatch = xmlText.match(/<\?xml[\s\S]*<\/PubmedArticleSet>/i);
  if (xmlMatch) {
    const fullXml = xmlMatch[0];
    pubmedArticles =
      fullXml.match(/<PubmedArticle\b[^>]*>[\s\S]*?<\/PubmedArticle>/gi) || [];
  }
}

// ============================================
// 4. HELPERS
// ============================================

function cleanXmlText(value = '') {
  return String(value)
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&apos;/g, "'")
    .replace(/&#x[a-fA-F0-9]+;/g, ' ')
    .replace(/&#\d+;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function findArticleBlockByPmid(pmid) {
  const pmidStr = String(pmid || '').trim();

  if (!pmidStr) return null;

  const patterns = [
    new RegExp(`<PMID[^>]*>\\s*${pmidStr}\\s*<\\/PMID>`, 'i'),
    new RegExp(`<ArticleId[^>]*IdType=["']pubmed["'][^>]*>\\s*${pmidStr}\\s*<\\/ArticleId>`, 'i'),
    new RegExp(`<ArticleId[^>]*>\\s*${pmidStr}\\s*<\\/ArticleId>`, 'i'),
    new RegExp(`>${pmidStr}<`, 'i')
  ];

  for (const pattern of patterns) {
    const match = pubmedArticles.find(block => pattern.test(block));
    if (match) return match;
  }

  return null;
}

// ============================================
// 5. PROCESAR ARTÍCULOS
// ============================================

const updatedArticles = articles.map(article => {
  const pmid = String(article.pmid || '').trim();
  const matchedArticle = findArticleBlockByPmid(pmid);

  if (!matchedArticle) {
    return {
      ...article,
      abstract: '',
      publication_types: [],
      mesh_terms: [],
      abstract_parse_status: `NO_MATCHING_PUBMED_ARTICLE (${pubmedArticles.length} blocks found)`
    };
  }

  const abstractParts = [];

  const abstractMatches =
    matchedArticle.matchAll(/<AbstractText\b[^>]*>([\s\S]*?)<\/AbstractText>/gi);

  for (const match of abstractMatches) {
    const text = cleanXmlText(match[1]);
    if (text) abstractParts.push(text);
  }

  if (abstractParts.length === 0) {
    const legacyMatch =
      matchedArticle.match(/<Abstract\b[^>]*>([\s\S]*?)<\/Abstract>/i);

    if (legacyMatch) {
      const text = cleanXmlText(legacyMatch[1]);
      if (text) abstractParts.push(text);
    }
  }

  const publicationTypes = [];
  const pubTypeMatches =
    matchedArticle.matchAll(/<PublicationType\b[^>]*>([\s\S]*?)<\/PublicationType>/gi);

  for (const match of pubTypeMatches) {
    const text = cleanXmlText(match[1]);
    if (text) publicationTypes.push(text);
  }

  const meshTerms = [];
  const meshMatches =
    matchedArticle.matchAll(/<DescriptorName\b[^>]*>([\s\S]*?)<\/DescriptorName>/gi);

  for (const match of meshMatches) {
    const text = cleanXmlText(match[1]);
    if (text) meshTerms.push(text);
  }

  const abstract = abstractParts.join('\n');

  return {
    ...article,
    abstract,
    publication_types: [...new Set(publicationTypes)],
    mesh_terms: [...new Set(meshTerms)],
    abstract_parse_status: abstract ? 'OK' : 'NO_ABSTRACT_TEXT_FOUND'
  };
});

// ============================================
// 6. STATS + DEBUG
// ============================================

const stats = {
  total_articles: articles.length,
  abstracts_found: updatedArticles.filter(a => a.abstract).length,
  no_match_count: updatedArticles.filter(a =>
    a.abstract_parse_status?.startsWith('NO_MATCHING')
  ).length,
  no_abstract_count: updatedArticles.filter(a =>
    a.abstract_parse_status === 'NO_ABSTRACT_TEXT_FOUND'
  ).length,
  pubmed_blocks_found: pubmedArticles.length,
  first_article_pmid: articles[0]?.pmid || null,
  first_article_title: articles[0]?.title?.slice(0, 100) || null
};

// ============================================
// 7. RETURN REAL PARA CONTINUAR PIPELINE
// ============================================

return [{
  json: {
    ...original,
    ...input,
    articles: updatedArticles,
    parsing_stats: stats,
    debug_pubmed_abstracts: {
      xmlTextPreview: xmlText.slice(0, 5000),
      containsPubmedArticle: xmlText.includes('<PubmedArticle'),
      containsPubmedArticleSet: xmlText.includes('<PubmedArticleSet'),
      containsPubmedBookArticle: xmlText.includes('<PubmedBookArticle'),
      pubmedArticlesFound: pubmedArticles.length
    }
  }
}];

const input = $input.first().json;
const articles = input.articles || [];

function includesAny(text, terms) {
  return terms.some(term => text.includes(term));
}

function getPublicationYear(pubdate) {
  const match = String(pubdate || '').match(/\b(19|20)\d{2}\b/);
  return match ? parseInt(match[0], 10) : null;
}

function containsExact(text, term) {
  const escaped = String(term || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  return new RegExp(`\\b${escaped}\\b`, 'i').test(String(text || ''));
}

function countMatches(text, terms) {
  return terms.filter(term => containsExact(text, term)).length;
}

// ============================================
// EXTRAER EXPOSICIÓN / OUTCOME DEL CLAIM
// ============================================

const claimText = String(
  input.claim_limpio ||
  input.original_claim ||
  input.claim ||
  ''
).toLowerCase();

const dc = input.claim_decomposition || {};

let claimExposureTerms = [];
let claimOutcomeTerms = [];

const claimIsSunTanning =
  /(bronce|broncearse|moreno|tomar el sol|sun exposure|sunlight|sunbathing|tanning|uv|ultraviolet|radiacion uv|radiación uv)/i.test(claimText);

const claimIsSkinCancer =
  /(cancer de piel|cáncer de piel|skin cancer|melanoma|skin neoplasms|carcinoma)/i.test(claimText);

if (Array.isArray(dc.exposure_terms)) {
  claimExposureTerms.push(...dc.exposure_terms);
}

if (Array.isArray(dc.outcome_terms)) {
  claimOutcomeTerms.push(...dc.outcome_terms);
}

// Fallbacks por dominio

if (/(bronce|broncearse|moreno|tomar el sol|sol|radiacion uv|radiación uv|ultraviolet|uv|sun exposure|sunlight|tanning)/i.test(claimText)) {
  claimExposureTerms.push(
    'sun exposure',
    'sunlight',
    'sunbathing',
    'tanning',
    'indoor tanning',
    'ultraviolet',
    'uv radiation',
    'ultraviolet rays',
    'solar radiation',
    'sunburn',
    'photoadaptation',
    'photoprotection'
  );
}

if (claimIsSkinCancer) {
  claimOutcomeTerms.push(
    'skin cancer',
    'skin neoplasms',
    'cutaneous melanoma',
    'melanoma',
    'basal cell carcinoma',
    'squamous cell carcinoma',
    'non-melanoma skin cancer',
    'cutaneous neoplasms',
    'skin carcinoma'
  );
} else if (/(cancer|cáncer|neoplasm|tumor|carcinoma)/i.test(claimText)) {
  claimOutcomeTerms.push(
    'cancer',
    'neoplasms',
    'neoplasm',
    'tumor',
    'tumors',
    'carcinoma',
    'incidence'
  );
}

if (/(vitamina d|vitamin d)/i.test(claimText)) {
  claimExposureTerms.push(
    'vitamin d',
    'vitamin d supplementation',
    '25-hydroxyvitamin d',
    'cholecalciferol'
  );
}

// Normalizar

claimExposureTerms = [...new Set(
  claimExposureTerms
    .map(t => String(t).toLowerCase().trim())
    .filter(Boolean)
)];

claimOutcomeTerms = [...new Set(
  claimOutcomeTerms
    .map(t => String(t).toLowerCase().trim())
    .filter(Boolean)
)];

// ============================================
// GRUPOS PARA PENALIZAR CONFUSIONES
// ============================================

const articlesWithQuality = articles.map(article => {
  const title = String(article.title || '').toLowerCase();
  const abstract = String(article.abstract || '').toLowerCase();
  const journal = String(article.journal || '').toLowerCase();

  const pubTypesArray = (article.publication_types || [])
    .map(t => String(t).toLowerCase())
    .map(t => t.replace(/-/g, ' '))
    .map(t => t.trim());

  const pubTypes = pubTypesArray.join(' ');
  const mesh = (article.mesh_terms || []).join(' ').toLowerCase();

  const fullText = `${title} ${abstract} ${journal} ${pubTypes} ${mesh}`;

  // =========================
  // 1. STUDY TYPE
  // =========================

  let study_type = article.study_type || 'UNKNOWN';

  if (title.includes('umbrella review') || abstract.includes('umbrella review')) {
    study_type = 'UMBRELLA_REVIEW';
  } else if (
    pubTypesArray.includes('meta analysis') &&
    pubTypesArray.includes('systematic review')
  ) {
    study_type = 'SYSTEMATIC_REVIEW_META_ANALYSIS';
  } else if (pubTypesArray.includes('meta analysis')) {
    study_type = 'META_ANALYSIS';
  } else if (pubTypesArray.includes('systematic review')) {
    study_type = 'SYSTEMATIC_REVIEW';
  } else if (
    (title.includes('systematic review') || abstract.includes('systematic review')) &&
    (title.includes('meta-analysis') || abstract.includes('meta-analysis'))
  ) {
    study_type = 'SYSTEMATIC_REVIEW_META_ANALYSIS';
  } else if (title.includes('meta-analysis') || abstract.includes('meta-analysis')) {
    study_type = 'META_ANALYSIS';
  } else if (
    title.includes('randomized') ||
    title.includes('randomised') ||
    title.includes('clinical trial') ||
    pubTypesArray.includes('randomized controlled trial')
  ) {
    study_type = 'RCT_OR_CLINICAL_TRIAL';
  } else if (title.includes('prospective') || title.includes('cohort') || abstract.includes('cohort')) {
    study_type = 'OBSERVATIONAL_COHORT';
  } else if (title.includes('case-control') || abstract.includes('case-control')) {
    study_type = 'CASE_CONTROL';
  } else if (title.includes('cross-sectional') || abstract.includes('cross-sectional')) {
    study_type = 'CROSS_SECTIONAL';
  }

  // =========================
  // 2. EVIDENCE WEIGHT
  // =========================

  let evidence_weight = 1;

  if (study_type === 'UMBRELLA_REVIEW') evidence_weight = 14;
  else if (study_type === 'SYSTEMATIC_REVIEW_META_ANALYSIS') evidence_weight = 12;
  else if (study_type === 'META_ANALYSIS') evidence_weight = 10;
  else if (study_type === 'SYSTEMATIC_REVIEW') evidence_weight = 9;
  else if (study_type === 'RCT_OR_CLINICAL_TRIAL') evidence_weight = 8;
  else if (study_type === 'OBSERVATIONAL_COHORT') evidence_weight = 5;
  else if (study_type === 'CASE_CONTROL') evidence_weight = 3;
  else if (study_type === 'CROSS_SECTIONAL') evidence_weight = 2;

  // =========================
  // 3. UNDERLYING EVIDENCE TYPE
  // =========================

  let underlying_evidence_type = 'UNCLEAR';

  const isActualRCT = pubTypesArray.includes('randomized controlled trial');

  const isNotReview =
    study_type !== 'SYSTEMATIC_REVIEW' &&
    study_type !== 'SYSTEMATIC_REVIEW_META_ANALYSIS' &&
    study_type !== 'META_ANALYSIS' &&
    study_type !== 'UMBRELLA_REVIEW';

  if (isActualRCT && isNotReview) {
    underlying_evidence_type = 'INTERVENTIONAL';
  } else if (
    fullText.includes('meta-analyses of prospective observational studies') ||
    fullText.includes('meta-analysis of prospective observational studies') ||
    fullText.includes('meta-analysis of cohort studies') ||
    fullText.includes('meta-analysis of observational studies') ||
    fullText.includes('umbrella review of meta-analyses of prospective observational studies') ||
    fullText.includes('observational studies as topic') ||
    mesh.includes('observational studies as topic')
  ) {
    underlying_evidence_type = 'OBSERVATIONAL_META_ANALYSIS';
  } else if (
    fullText.includes('systematic review') &&
    (
      fullText.includes('association') ||
      fullText.includes('associated with') ||
      fullText.includes('prospective study') ||
      fullText.includes('epic cohort') ||
      fullText.includes('prospective investigation')
    )
  ) {
    underlying_evidence_type = 'OBSERVATIONAL_REVIEW';
  } else if (
    fullText.includes('prospective cohort') ||
    fullText.includes('cohort study') ||
    fullText.includes('observational study') ||
    fullText.includes('case-control') ||
    fullText.includes('cross-sectional') ||
    mesh.includes('cohort studies') ||
    mesh.includes('prospective studies')
  ) {
    underlying_evidence_type = 'OBSERVATIONAL';
  } else if (
    (
      fullText.includes('animal model') ||
      fullText.includes('mouse model') ||
      fullText.includes('mice') ||
      fullText.includes('rats') ||
      fullText.includes('murine') ||
      fullText.includes('in vitro')
    ) &&
    !mesh.includes('humans') &&
    !fullText.includes('systematic review') &&
    !fullText.includes('meta-analysis')
  ) {
    underlying_evidence_type = 'PRECLINICAL';
  }

  let causal_inference_strength =
    underlying_evidence_type === 'INTERVENTIONAL'
      ? 'MODERATE_TO_HIGH'
      : underlying_evidence_type === 'OBSERVATIONAL_META_ANALYSIS'
      ? 'LOW_TO_MODERATE'
      : underlying_evidence_type === 'OBSERVATIONAL_REVIEW'
      ? 'LOW_TO_MODERATE'
      : underlying_evidence_type === 'OBSERVATIONAL'
      ? 'LOW'
      : underlying_evidence_type === 'PRECLINICAL'
      ? 'VERY_LOW'
      : 'UNCLEAR';

  // =========================
  // 4. HUMAN / OUTCOMES
  // =========================

  const humanIndicators = [
    'humans', 'human', 'patients', 'participants', 'adults',
    'men', 'women', 'population', 'population-based',
    'epidemiology', 'cohort', 'prospective', 'retrospective',
    'case-control', 'cross-sectional', 'clinical trial',
    'randomized', 'randomised', 'meta-analysis',
    'systematic review', 'umbrella review'
  ];

  const animalIndicators = [
    'mice', 'mouse', 'rat', 'rats', 'murine',
    'animal model', 'in vitro', 'cell line', 'zebrafish', 'rabbit'
  ];

  const hasHumanSignals = includesAny(fullText, humanIndicators);
  const hasAnimalSignals = includesAny(fullText, animalIndicators);

  const isClearlyAnimalOnly =
    hasAnimalSignals &&
    !hasHumanSignals &&
    !mesh.includes('humans');

  const is_human_evidence =
    !isClearlyAnimalOnly && (
      hasHumanSignals ||
      underlying_evidence_type === 'INTERVENTIONAL' ||
      underlying_evidence_type === 'OBSERVATIONAL_META_ANALYSIS' ||
      underlying_evidence_type === 'OBSERVATIONAL_REVIEW' ||
      underlying_evidence_type === 'OBSERVATIONAL'
    );

  const hardOutcomeTerms = [
    'mortality', 'death', 'cancer', 'neoplasm',
    'cardiovascular events', 'myocardial infarction', 'stroke',
    'hospitalization', 'incidence', 'melanoma', 'skin neoplasms'
  ];

  const surrogateOutcomeTerms = [
    'biomarker', 'blood pressure', 'glucose', 'insulin',
    'cholesterol', 'inflammatory marker', 'cytokine', 'oxidative stress'
  ];

  const has_hard_outcomes = includesAny(fullText, hardOutcomeTerms);
  const has_surrogate_outcomes = includesAny(fullText, surrogateOutcomeTerms);

  // =========================
  // 5. RELEVANCE CLAIM ↔ ARTICLE
  // NUEVO BLOQUE IMPORTANTE
  // =========================

  const exposureMatches = countMatches(fullText, claimExposureTerms);
  const outcomeMatches = countMatches(fullText, claimOutcomeTerms);

  const titleExposureMatches = countMatches(title, claimExposureTerms);
  const titleOutcomeMatches = countMatches(title, claimOutcomeTerms);

  const meshExposureMatches = countMatches(mesh, claimExposureTerms);
  const meshOutcomeMatches = countMatches(mesh, claimOutcomeTerms);

  const has_exposure = exposureMatches > 0;
  const has_outcome = outcomeMatches > 0;

  const strong_relation_match =
    has_exposure &&
    has_outcome &&
    (
      titleExposureMatches > 0 ||
      titleOutcomeMatches > 0 ||
      meshExposureMatches > 0 ||
      meshOutcomeMatches > 0
    );

  let relevance_score = 0;

  if (has_exposure) relevance_score += 30;
  if (has_outcome) relevance_score += 30;
  if (strong_relation_match) relevance_score += 25;

  if (titleExposureMatches > 0) relevance_score += 10;
  if (titleOutcomeMatches > 0) relevance_score += 10;
  if (meshExposureMatches > 0) relevance_score += 8;
  if (meshOutcomeMatches > 0) relevance_score += 8;

  // Penalización fuerte: outcome sí, exposición no
  if (!has_exposure && has_outcome) {
    relevance_score -= 35;
  }

  // Penalización fuerte para vitamina D cuando el claim es bronceado/sol
  const articleIsVitaminD =
    /\bvitamin d\b|\bvitamina d\b|25-hydroxyvitamin d|cholecalciferol|dietary supplements|supplementation/i.test(fullText);

  if (claimIsSunTanning && articleIsVitaminD && !/tanning|sunbathing|sun exposure|sunlight|uv radiation|ultraviolet/i.test(title)) {
    relevance_score -= 45;
  }

  // Penalización para cáncer general cuando el claim es cáncer de piel
  const articleIsGeneralCancer =
    /\bcancer\b|\bneoplasms\b|\bincidence\b|\bmortality\b/i.test(fullText) &&
    !/skin cancer|skin neoplasms|melanoma|basal cell carcinoma|squamous cell carcinoma|cutaneous/i.test(fullText);

  if (claimIsSkinCancer && articleIsGeneralCancer) {
    relevance_score -= 40;
  }

  const articlePrimaryMortality =
  /all-cause mortality|mortality rate|life expectancy|cause of death/i.test(fullText);

if (
  claimIsSkinCancer &&
  articlePrimaryMortality
) {
  relevance_score -= 35;
}

  relevance_score = Math.max(0, Math.min(100, relevance_score));

  const exposure_match_score = Math.max(
    0,
    Math.min(
      100,
      (has_exposure ? 60 : 0) +
      (titleExposureMatches > 0 ? 20 : 0) +
      (meshExposureMatches > 0 ? 20 : 0)
    )
  );

  const outcome_match_score = Math.max(
    0,
    Math.min(
      100,
      (has_outcome ? 60 : 0) +
      (titleOutcomeMatches > 0 ? 20 : 0) +
      (meshOutcomeMatches > 0 ? 20 : 0)
    )
  );

let semanticPenalty = 0;

if (claimIsSkinCancer && articlePrimaryMortality) {
  semanticPenalty += 35;
}

if (claimIsSkinCancer && articleIsGeneralCancer) {
  semanticPenalty += 40;
}

if (claimIsSunTanning && articleIsVitaminD) {
  semanticPenalty += 45;
}

  const semantic_claim_match_score = Math.max(
    0,
    Math.min(
      100,
      Math.round(
  exposure_match_score * 0.55 +
  outcome_match_score * 0.35 +
  (strong_relation_match ? 10 : 0) -
  semanticPenalty
)
    )
  );

  // =========================
  // 6. RISK OF BIAS
  // =========================

  let risk_of_bias_score = 0;
  const risk_of_bias_flags = [];

  if (includesAny(fullText, ['heterogeneity', 'i2', 'i²'])) {
    risk_of_bias_score += 2;
    risk_of_bias_flags.push('heterogeneity_mentioned');
  }

  if (includesAny(fullText, ['residual confounding', 'unmeasured confounding', 'confounding'])) {
    risk_of_bias_score += 3;
    risk_of_bias_flags.push('confounding_risk');
  }

  if (includesAny(fullText, ['self-reported', 'food frequency questionnaire', 'ffq'])) {
    risk_of_bias_score += 2;
    risk_of_bias_flags.push('self_reported_diet');
  }

  if (includesAny(fullText, ['recall bias'])) {
    risk_of_bias_score += 2;
    risk_of_bias_flags.push('recall_bias');
  }

  if (includesAny(fullText, ['low certainty', 'low-quality evidence', 'very low certainty'])) {
    risk_of_bias_score += 2;
    risk_of_bias_flags.push('low_certainty_evidence');
  }

  if (includesAny(fullText, ['publication bias', 'funnel plot', 'small-study effects'])) {
    risk_of_bias_score += 2;
    risk_of_bias_flags.push('publication_bias');
  }

  if (underlying_evidence_type === 'OBSERVATIONAL') {
    risk_of_bias_score += 3;
    risk_of_bias_flags.push('observational_primary');
  } else if (
    underlying_evidence_type === 'OBSERVATIONAL_REVIEW' ||
    underlying_evidence_type === 'OBSERVATIONAL_META_ANALYSIS'
  ) {
    risk_of_bias_score += 2;
    risk_of_bias_flags.push('observational_synthesis');
  }

  let risk_of_bias_estimate = 'LOW';
  if (risk_of_bias_score >= 8) risk_of_bias_estimate = 'HIGH';
  else if (risk_of_bias_score >= 4) risk_of_bias_estimate = 'MODERATE';

  // =========================
  // 7. MECHANISTIC SEPARATION
  // =========================

  const mechanisticTerms = [
    'in vitro', 'cell culture', 'animal model', 'mouse', 'mice', 'murine', 'rat model'
  ];

  const humanClinicalTerms = [
    'randomized', 'randomised', 'clinical trial', 'cohort', 'prospective',
    'case-control', 'cross-sectional', 'meta-analysis', 'systematic review',
    'humans', 'patients', 'participants'
  ];

  const hasMechanistic = includesAny(fullText, mechanisticTerms);
  const hasHumanClinical = includesAny(fullText, humanClinicalTerms) || is_human_evidence;

  let evidence_type_classification = 'HUMAN_CLINICAL';

  const isAnimalOnly = mesh.includes('animals') && !mesh.includes('humans');

  if (isAnimalOnly) {
    evidence_type_classification = 'PRECLINICAL_ANIMAL_ONLY';
  } else if (hasMechanistic && !hasHumanClinical) {
    evidence_type_classification = 'MECHANISTIC_ONLY';
  } else if (hasMechanistic && hasHumanClinical) {
    evidence_type_classification = 'MIXED_HUMAN_AND_MECHANISTIC';
  } else if (!hasHumanClinical && !hasMechanistic) {
    evidence_type_classification = 'UNCLEAR';
  }

  const mechanistic_note =
    evidence_type_classification === 'MECHANISTIC_ONLY'
      ? 'Este artículo es mayoritariamente mecanicista/preclínico. No debe usarse como evidencia clínica directa.'
      : evidence_type_classification === 'MIXED_HUMAN_AND_MECHANISTIC'
      ? 'El artículo mezcla evidencia clínica con lenguaje mecanicista. Separar asociación clínica de mecanismo.'
      : '';

  // =========================
  // 8. TEMPORAL WEIGHTING
  // =========================

  const publication_year = getPublicationYear(article.pubdate);
  let temporal_weight = 0;
  let temporal_note = '';

  if (publication_year >= 2022) {
    temporal_weight = 3;
    temporal_note = 'Evidencia muy reciente.';
  } else if (publication_year >= 2019) {
    temporal_weight = 2;
    temporal_note = 'Evidencia reciente.';
  } else if (publication_year >= 2015) {
    temporal_weight = 0;
    temporal_note = 'Evidencia moderadamente actualizada.';
  } else if (publication_year >= 2010) {
    temporal_weight = -2;
    temporal_note = 'Evidencia con más de 10 años. Verificar si hay revisiones más recientes.';
  } else if (publication_year) {
    temporal_weight = -4;
    temporal_note = 'Evidencia antigua. Debe tener poco peso si existe evidencia más reciente.';
  }

  if (
    publication_year >= 2020 &&
    ['UMBRELLA_REVIEW', 'SYSTEMATIC_REVIEW_META_ANALYSIS', 'META_ANALYSIS'].includes(study_type)
  ) {
    temporal_weight += 2;
    temporal_note += ' Revisión de alta jerarquía reciente.';
  }

  // =========================
  // 9. CAUSAL OVERSTATEMENT
  // =========================

  const causalClaimTerms = [
    'causes', 'causal', 'causality', 'causal relationship', 'protects', 'protective',
    'prevents', 'prevention', 'leads to', 'results in', 'induces', 'triggers',
    'drives', 'promotes', 'inhibits', 'blocks'
  ];

  const causal_language_in_title = causalClaimTerms.some(term => title.includes(term));
  const causal_language_in_abstract = causalClaimTerms.some(term => abstract.includes(term));
  const causalLanguageInArticle = causal_language_in_title || causal_language_in_abstract;

  const weakCausalBase = [
    'OBSERVATIONAL', 'OBSERVATIONAL_REVIEW', 'OBSERVATIONAL_META_ANALYSIS'
  ].includes(underlying_evidence_type);

  const causal_overstatement_detected = causalLanguageInArticle && weakCausalBase;

  let causal_overstatement_severity = 'NONE';

  if (causal_overstatement_detected) {
    if (underlying_evidence_type === 'OBSERVATIONAL') {
      causal_overstatement_severity = 'HIGH';
    } else if (underlying_evidence_type === 'OBSERVATIONAL_REVIEW') {
      causal_overstatement_severity = 'MODERATE';
    } else if (underlying_evidence_type === 'OBSERVATIONAL_META_ANALYSIS') {
      causal_overstatement_severity = 'MODERATE_TO_HIGH';
    }
  }

  const causal_overstatement_note = causal_overstatement_detected
    ? 'El artículo usa lenguaje causal/fuerte, pero la base de evidencia parece observacional. Interpretar como asociación salvo evidencia experimental fuerte.'
    : '';

  // =========================
  // 10. FINAL QUALITY LEVEL
  // =========================

  let evidence_level = 'BAJO';

  if (evidence_weight >= 12 && risk_of_bias_estimate !== 'HIGH') {
    evidence_level = 'ALTO';
  } else if (evidence_weight >= 8 && risk_of_bias_estimate !== 'HIGH') {
    evidence_level = 'MODERADO_ALTO';
  } else if (evidence_weight >= 5) {
    evidence_level = 'MODERADO';
  }

  const adjusted_evidence_weight = Math.max(
    0,
    evidence_weight + temporal_weight - Math.floor(risk_of_bias_score / 3)
  );

  // Corrección meta-analysis no-interventional falso

  if (
    (study_type === 'META_ANALYSIS' ||
      study_type === 'SYSTEMATIC_REVIEW_META_ANALYSIS' ||
      study_type === 'SYSTEMATIC_REVIEW') &&
    underlying_evidence_type === 'INTERVENTIONAL'
  ) {
    underlying_evidence_type = 'OBSERVATIONAL_REVIEW';
    causal_inference_strength = 'LOW_TO_MODERATE';
  }

  return {
    ...article,

    study_type,
    evidence_weight,
    adjusted_evidence_weight,
    evidence_level,

    underlying_evidence_type,
    causal_inference_strength,

    is_human_evidence,
    has_hard_outcomes,
    has_surrogate_outcomes,

    // NUEVO: relevancia real
    relevance_score,
    has_exposure,
    has_outcome,
    strong_relation_match,
    exposure_match_score,
    outcome_match_score,
    semantic_claim_match_score,

    relevance_debug: {
      claim_exposure_terms: claimExposureTerms,
      claim_outcome_terms: claimOutcomeTerms,
      exposure_matches: exposureMatches,
      outcome_matches: outcomeMatches,
      title_exposure_matches: titleExposureMatches,
      title_outcome_matches: titleOutcomeMatches,
      mesh_exposure_matches: meshExposureMatches,
      mesh_outcome_matches: meshOutcomeMatches,
      article_is_vitamin_d: articleIsVitaminD,
      article_is_general_cancer: articleIsGeneralCancer
    },

    risk_of_bias_score,
    risk_of_bias_estimate,
    risk_of_bias_flags,

    evidence_type_classification,
    mechanistic_note,
    has_mechanistic_speculation:
      evidence_type_classification === 'MECHANISTIC_ONLY' ||
      evidence_type_classification === 'MIXED_HUMAN_AND_MECHANISTIC',

    publication_year,
    temporal_weight,
    temporal_note,
    is_recent_high_quality: temporal_weight >= 4,

    causal_overstatement_detected,
    causal_overstatement_severity,
    causal_overstatement_note,
    causal_language_in_title,
    causal_language_in_abstract
  };
});

return [{
  json: {
    ...input,
    articles: articlesWithQuality
  }
}];

const input = $input.first().json;
const articles = input.articles || [];

// ============================================
// USAR CANONICAL PARA CONSENSO PONDERADO
// ============================================

// Filtrar artículos con score > 0 (usando canonical si existe)
const relevantArticles = articles.filter(a => {
  const score = a.final_score || 
                a.canonical?.final_score || 
                a.canonical?.deterministic_confidence || 
                a.relevance_score || 0;
  return score > 0;
});

let weightedSupport = 0;
let weightedContradict = 0;
let weightedNeutral = 0;
let weightedTotal = 0;

const classifiedArticles = relevantArticles.map(article => {
  const relation = article.relation_to_claim || 'UNCLEAR';

  // Priorizar: final_score > deterministic_confidence > relevance_score
  const weight = article.final_score || 
                 (article.canonical?.deterministic_confidence * 100) ||
                 article.canonical?.final_score ||
                 article.relevance_score || 
                 1;

  weightedTotal += weight;

  if (relation === 'SUPPORTS_CLAIM') {
    weightedSupport += weight;
  } else if (relation === 'CONTRADICTS_CLAIM') {
    weightedContradict += weight;
  } else {
    weightedNeutral += weight;
  }

  return {
    pmid: article.pmid,
    title: article.title,
    relevance_score: article.relevance_score,
    final_score: article.final_score,
    deterministic_confidence: article.canonical?.deterministic_confidence || null,
    evidence_level: article.evidence_level,
    study_type: article.canonical?.study_type || article.study_type,
    underlying_evidence_type: article.canonical?.underlying_type || article.underlying_evidence_type,
    causal_inference_strength: article.causal_inference_strength,
    relation_to_claim: relation,
    direction_confidence: article.direction_confidence
  };
});

let consensus_level = 'INSUFFICIENT';
let dominantDirection = 'UNCLEAR';
let dominantWeight = 0;

if (weightedSupport > dominantWeight) {
  dominantWeight = weightedSupport;
  dominantDirection = 'SUPPORTS_CLAIM';
}
if (weightedContradict > dominantWeight) {
  dominantWeight = weightedContradict;
  dominantDirection = 'CONTRADICTS_CLAIM';
}
if (weightedNeutral > dominantWeight) {
  dominantWeight = weightedNeutral;
  dominantDirection = 'NEUTRAL_OR_DOES_NOT_SUPPORT';
}

const totalWeight = weightedSupport + weightedContradict + weightedNeutral;
const dominantRatio = totalWeight > 0 ? dominantWeight / totalWeight : 0;

// Criterios de consenso más estrictos
if (totalWeight >= 100) {
  if (dominantRatio >= 0.7) consensus_level = 'STRONG';
  else if (dominantRatio >= 0.55) consensus_level = 'MODERATE';
  else consensus_level = 'MIXED';
} else if (totalWeight >= 50) {
  consensus_level = 'WEAK';
} else if (totalWeight >= 20) {
  consensus_level = 'VERY_WEAK';
}

const evidenceConsensus = {
  articles_considered: relevantArticles.length,
  supporting_count: relevantArticles.filter(a => a.relation_to_claim === 'SUPPORTS_CLAIM').length,
  contradicting_count: relevantArticles.filter(a => a.relation_to_claim === 'CONTRADICTS_CLAIM').length,
  neutral_or_unclear_count: relevantArticles.filter(a => 
    a.relation_to_claim !== 'SUPPORTS_CLAIM' && a.relation_to_claim !== 'CONTRADICTS_CLAIM'
  ).length,
  weighted_support: weightedSupport,
  weighted_contradict: weightedContradict,
  weighted_neutral: weightedNeutral,
  total_weighted: totalWeight,
  dominant_direction: dominantDirection,
  dominant_ratio: dominantRatio,
  consensus_level: consensus_level,
  classified_articles: classifiedArticles,
  note: 'Consenso ponderado usando final_score > deterministic_confidence > relevance_score. Los valores vienen del objeto canonical cuando está disponible.'
};

return [{
  json: {
    ...input,
    evidence_consensus: evidenceConsensus
  }
}];

