// ============================================
// CONSTRUIR CONSENSO EVIDENCIA — VERSIÓN CORREGIDA
// Distingue entre:
//   A) Consenso real de apoyo/contradicción
//   B) Unanimidad de UNCLEAR (= artículos no relevantes para el claim)
//   C) Evidencia insuficiente
// ============================================

const input = $input.first().json;
const articles = input.articles || [];

// ============================================
// FUNCIÓN PRINCIPAL DE CONSENSO
// ============================================

function calcConsensusLevel(supporting, contradicting, unclear, total, insufficientRelevance) {

  if (total === 0) {
    return {
      consensus_level: 'INSUFFICIENT',
      consensus_note: 'No hay artículos para evaluar.',
      gemini_instruction: 'No articles available. Respond with EVIDENCIA_INSUFICIENTE and explain no relevant evidence was found.'
    };
  }

  // Caso crítico: artículos no son relevantes para el claim
  if (insufficientRelevance) {
    return {
      consensus_level: 'INSUFFICIENT',
      consensus_note: 'Los artículos recuperados no son directamente relevantes para evaluar el claim. La query de búsqueda puede haber sido subóptima.',
      gemini_instruction: 'CRITICAL: The retrieved articles do not directly address this specific claim. You MUST respond with EVIDENCIA_INSUFICIENTE. Explain clearly that the available evidence does not allow evaluation of this claim, and that the search may have returned tangentially related articles. Do NOT invent a verdict based on indirect evidence.'
    };
  }

  const unclearRatio     = unclear / total;
  const supportRatio     = supporting / total;
  const contradictRatio  = contradicting / total;

  // Todos o casi todos UNCLEAR → no es consenso, es ausencia de evidencia directa
  if (unclearRatio >= 0.8) {
    return {
      consensus_level: 'INSUFFICIENT',
      consensus_note: `El ${Math.round(unclearRatio * 100)}% de los artículos no tiene dirección clara respecto al claim. Esto indica falta de evidencia aplicable, NO consenso.`,
      gemini_instruction: 'Most articles have UNCLEAR relation to this specific claim. This means the evidence base is insufficient to evaluate it — it does NOT mean the claim is false. Respond with EVIDENCIA_INSUFICIENTE and explain the distinction between "no evidence found" and "evidence contradicts the claim".'
    };
  }

  // Evidencia mixta real (apoyo Y contradicción)
  if (supporting > 0 && contradicting > 0) {
    const balance = Math.abs(supportRatio - contradictRatio);
    if (balance < 0.25) {
      return {
        consensus_level: 'MIXED',
        consensus_note: 'Evidencia dividida de forma aproximadamente igual entre apoyo y contradicción.',
        gemini_instruction: ''
      };
    }
    if (supportRatio > contradictRatio) {
      return {
        consensus_level: 'WEAK',
        consensus_note: 'Tendencia de apoyo al claim pero con contradicciones significativas.',
        gemini_instruction: ''
      };
    }
    return {
      consensus_level: 'WEAK',
      consensus_note: 'Tendencia contradictoria al claim pero con algunos apoyos.',
      gemini_instruction: ''
    };
  }

  // Solo apoyo, sin contradicciones
  if (supporting > 0 && contradicting === 0) {
    if (supportRatio >= 0.7 && supporting >= 3) {
      return {
        consensus_level: 'STRONG',
        consensus_note: `${supporting} de ${total} artículos apoyan el claim sin contradicciones.`,
        gemini_instruction: ''
      };
    }
    if (supportRatio >= 0.5 || supporting >= 2) {
      return {
        consensus_level: 'MODERATE',
        consensus_note: 'Apoyo moderado al claim, sin contradicciones directas.',
        gemini_instruction: ''
      };
    }
    return {
      consensus_level: 'WEAK',
      consensus_note: 'Apoyo débil al claim (pocos artículos relevantes).',
      gemini_instruction: ''
    };
  }

  // Solo contradicciones, sin apoyo
  if (contradicting > 0 && supporting === 0) {
    if (contradictRatio >= 0.7 && contradicting >= 3) {
      return {
        consensus_level: 'STRONG',
        consensus_note: `${contradicting} de ${total} artículos contradicen el claim.`,
        gemini_instruction: ''
      };
    }
    return {
      consensus_level: 'MODERATE',
      consensus_note: 'Contradicción moderada al claim.',
      gemini_instruction: ''
    };
  }

  // Fallback
  return {
    consensus_level: 'INSUFFICIENT',
    consensus_note: 'No hay evidencia directa suficiente para determinar consenso.',
    gemini_instruction: 'Evidence is insufficient to evaluate this claim. Respond with EVIDENCIA_INSUFICIENTE.'
  };
}

// ============================================
// CLASIFICAR ARTÍCULOS POR DIRECCIÓN
// ============================================

let supporting_count   = 0;
let contradicting_count = 0;
let neutral_count       = 0;
let unclear_count       = 0;

let weighted_support   = 0;
let weighted_contradict = 0;
let weighted_neutral    = 0;
let weighted_unclear    = 0;

const classified_articles = [];

for (const article of articles) {
  const relation = article.relation_to_claim || 'UNCLEAR';
  const score    = article.final_score || 0;
  const conf     = article.direction_confidence || 'LOW';

  // Penalizar artículos con dirección poco confiable
  const confidenceMultiplier = conf === 'HIGH' ? 1.0 : conf === 'MODERATE' ? 0.7 : 0.3;
  const effectiveWeight = score * confidenceMultiplier;

  if (relation === 'SUPPORTS_CLAIM') {
    supporting_count++;
    weighted_support += effectiveWeight;
  } else if (relation === 'CONTRADICTS_CLAIM') {
    contradicting_count++;
    weighted_contradict += effectiveWeight;
  } else if (relation === 'DOES_NOT_SUPPORT_CLAIM') {
    neutral_count++;
    weighted_neutral += effectiveWeight;
  } else {
    unclear_count++;
    weighted_unclear += effectiveWeight;
  }

  classified_articles.push({
    pmid: article.pmid,
    title: article.title,
    relevance_score: article.relevance_score,
    final_score: article.final_score,
    evidence_level: article.evidence_level,
    study_type: article.study_type,
    underlying_evidence_type: article.underlying_evidence_type,
    causal_inference_strength: article.causal_inference_strength,
    relation_to_claim: relation,
    direction_confidence: conf
  });
}

const articles_considered = articles.length;
const total_weighted = weighted_support + weighted_contradict + weighted_neutral + weighted_unclear;

// Calcular dirección dominante
let dominant_direction = 'UNCLEAR';
let dominant_weight    = 0;

const directions = [
  { name: 'SUPPORTS_CLAIM',          weight: weighted_support },
  { name: 'CONTRADICTS_CLAIM',       weight: weighted_contradict },
  { name: 'DOES_NOT_SUPPORT_CLAIM',  weight: weighted_neutral },
  { name: 'UNCLEAR',                 weight: weighted_unclear }
];

directions.sort((a, b) => b.weight - a.weight);
if (directions[0].weight > 0) {
  dominant_direction = directions[0].name;
  dominant_weight    = directions[0].weight;
}

const dominant_ratio = total_weighted > 0 ? dominant_weight / total_weighted : 0;

// ============================================
// DETECTAR SI LOS ARTÍCULOS SON INSUFICIENTEMENTE RELEVANTES
// ============================================

const insufficient_relevance = input.insufficient_relevance || false;
const avg_relevance = articles.length > 0
  ? articles.reduce((sum, a) => sum + (a.relevance_score || 0), 0) / articles.length
  : 0;

// Si el relevance promedio es muy negativo y ningún artículo tiene match fuerte
const no_strong_matches = articles.every(a => !a.strong_relation_match);
const low_avg_relevance  = avg_relevance < -20;
const computed_insufficient = insufficient_relevance || (no_strong_matches && low_avg_relevance && unclear_count === articles_considered);

// ============================================
// CALCULAR CONSENSUS LEVEL
// ============================================

const consensusResult = calcConsensusLevel(
  supporting_count,
  contradicting_count,
  unclear_count + neutral_count,
  articles_considered,
  computed_insufficient
);

// ============================================
// OUTPUT
// ============================================

const evidence_consensus = {
  articles_considered,
  supporting_count,
  contradicting_count,
  neutral_or_unclear_count: unclear_count + neutral_count,
  weighted_support,
  weighted_contradict,
  weighted_neutral,
  weighted_unclear,
  total_weighted,
  dominant_direction,
  dominant_ratio: Math.round(dominant_ratio * 100) / 100,
  consensus_level: consensusResult.consensus_level,
  consensus_note: consensusResult.consensus_note,
  gemini_instruction: consensusResult.gemini_instruction,
  classified_articles,
  insufficient_relevance: computed_insufficient,
  avg_relevance_score: Math.round(avg_relevance * 10) / 10
};

console.log('=== CONSENSO EVIDENCIA ===');
console.log('Articles:', articles_considered);
console.log('Supporting:', supporting_count, '| Contradicting:', contradicting_count, '| Unclear:', unclear_count);
console.log('Insufficient relevance:', computed_insufficient);
console.log('Consensus level:', consensusResult.consensus_level);
console.log('Note:', consensusResult.consensus_note);

return [{
  json: {
    ...input,
    evidence_consensus,
    insufficient_relevance: computed_insufficient
  }
}];

const input = $input.first().json;
const articles = input.articles || [];

const claimText = String(input.claim_limpio || input.original_claim || '').toLowerCase();
const originalClaim = String(input.original_claim || '').toLowerCase();
const dc = input.claim_decomposition || {};

const claimDirection = (() => {
  // Detectar beneficial (incluye "cura" y "acorta")
  if (/(reduce|disminuye|baja|protege|previene|menor riesgo|lower risk|protective|beneficial|cura|curar|acorta|acortar|mejora|alivia)/i.test(claimText)) {
    return 'beneficial';
  }
  // Detectar harmful
  if (/(aumenta|causa|provoca|mayor riesgo|higher risk|harmful|increased risk|adverse|riesgo|daña|dañar|perjudica|es malo para|es perjudicial|deteriora)/i.test(claimText)) {
    return 'harmful';
  }
  return 'unclear';
})();

// Detectar si el claim es sobre un beneficio específico
const claimFocusesOnBenefit = /(acorta|acortar|reduce|reduces|disminuye|mejora|previene|protege|beneficio|beneficioso|alivia|aliviar|acelera|acelerar|mejorar|reducir duración|acortar duración)/i.test(claimText);

// Detectar si el claim original es sobre daño
const claimIsAboutHarm = /(daña|dañar|perjudica|es malo para|es perjudicial|deteriora|causa daño|provoca daño|toxicidad|renal damage|kidney damage|harmful|damage|toxicity)/i.test(originalClaim);

// ============================================
// TÉRMINOS DE DIRECCIÓN
// ============================================

const benefitTerms = [
  'lower risk', 'reduced risk', 'decreased risk', 'inverse association',
  'protective', 'beneficial', 'risk reduction', 'lower incidence',
  'reduced incidence', 'lower mortality', 'reduced mortality',
  'protect against', 'protective effect', 'favorable outcome',
  'favourable outcome', 'smoking cessation', 'cessation reduced',
  'reduce the risk', 'reducing the risk', 'substantially reducing risk',
  'no association', 'not associated', 'null association',
  'no significant association', 'not significant', 'inconclusive'
];

const harmTerms = [
  'higher risk', 'increased risk', 'elevated risk', 'greater risk',
  'harmful', 'adverse', 'positive association', 'positively associated',
  'increased incidence', 'higher incidence', 'increased mortality',
  'higher mortality', 'risk factor', 'risk factors',
  'major environmental hazard', 'environmental hazard', 'known carcinogen',
  'carcinogen associated', 'associated with increased',
  'significantly associated with increased', 'linked to increased',
  'increased odds', 'higher odds', 'increased hazard', 'attributable to',
  'attributable risk', 'population attributable', 'supports the hypothesis',
  'may contribute to', 'highest risk', 'pack-years', 'smoking intensity',
  'causal relationship', 'causes', 'induces', 'promotes', 'drives'
];

const nullTerms = [
  'no association', 'not associated', 'no significant association',
  'not significant', 'null association', 'no evidence',
  'insufficient evidence', 'inconclusive', 'did not support',
  'does not support', 'do not support', 'no significant difference',
  'not with cancer', 'no further reduction', 'no apparent association',
  'no risk difference', 'not proven', 'no evidence for',
  'not associated with increased risk', 'equal occurrences',
  'no significant relationship', 'no relationship', 'not related to the risk',
  'not related to risk', 'no causal relationship', 'not causal',
  'does not induce', 'do not induce', 'not induce',
  'no damage', 'no renal damage', 'does not cause',
  'do not cause', 'not cause', 'no adverse',
  'no harmful', 'not harmful', 'no toxicity',
  'does not impair', 'do not impair', 'not impair',
  'did not alter', 'does not alter', 'not alter',
  'no effect on', 'no significant effect', 'no adverse effect'
];

const uncertaintyTerms = [
  'may', 'might', 'could', 'suggest', 'suggests', 'possibly',
  'potentially', 'limited evidence', 'low certainty', 'very low certainty',
  'heterogeneity', 'residual confounding', 'bias', 'confounding',
  'controversial', 'less well-characterized', 'warrants further',
  'needs further', 'requires further', 'further research'
];

// ============================================
// FUNCIONES AUXILIARES
// ============================================

function normalizeText(text) {
  return String(text || '')
    .toLowerCase()
    .replace(/\n/g, ' ')
    .replace(/consumption/g, 'intake')
    .replace(/dietary/g, '')
    .replace(/risk of/g, 'risk')
    .replace(/\s+/g, ' ')
    .trim();
}

function extractConclusion(abstract) {
  const conclusionMarkers = [
    /conclusion(?:s?):\s*([^.!?]+[.!?])/i,
    /in conclusion,\s*([^.!?]+[.!?])/i,
    /we conclude that\s*([^.!?]+[.!?])/i,
    /our findings suggest that\s*([^.!?]+[.!?])/i,
    /these results indicate that\s*([^.!?]+[.!?])/i,
    /this study demonstrates that\s*([^.!?]+[.!?])/i,
    /we found that\s*([^.!?]+[.!?])/i
  ];

  for (const pattern of conclusionMarkers) {
    const match = abstract.match(pattern);
    if (match) return match[1];
  }

  const sentences = abstract.split(/[.!?]+/).filter(s => s.trim().length > 20);
  if (sentences.length >= 2) {
    return sentences.slice(-2).join('. ');
  }

  return abstract;
}

function ciCrossesOne(ciText) {
  if (!ciText) return null;
  const nums = String(ciText).match(/[0-9]+(?:\.[0-9]+)?/g);
  if (!nums || nums.length < 2) return null;
  const low = Number(nums[0]);
  const high = Number(nums[1]);
  return low <= 1 && high >= 1;
}

function extractRiskMetrics(sentence) {
  const metrics = [];
  const regex = /\b(hr|rr|or|hazard ratio|risk ratio|relative risk|odds ratio)\b\s*(?:=|of|:)?\s*([0-9]+(?:\.[0-9]+)?)(?:\s*\(([^)]*)\))?/gi;
  let match;
  while ((match = regex.exec(sentence)) !== null) {
    metrics.push({
      metric: match[1].toUpperCase(),
      value: Number(match[2]),
      ci: match[3] || null,
      ci_crosses_one: ciCrossesOne(match[3] || null)
    });
  }
  return metrics;
}

function hasMetricAboveOne(sentence) {
  const metrics = extractRiskMetrics(sentence);
  return metrics.some(m => {
    if (m.value <= 1.05) return false;
    if (m.ci_crosses_one === true) return false;
    return true;
  });
}

function hasMetricBelowOne(sentence) {
  const metrics = extractRiskMetrics(sentence);
  return metrics.some(m => {
    if (m.value >= 0.95) return false;
    if (m.ci_crosses_one === true) return false;
    return true;
  });
}

function hasStrongNullWithRiskMetric(sentence) {
  return (
    /(?:ci|confidence interval)[^.;,]*(?:0\.|1\.0|1\.00)[^.;,]*/i.test(sentence) &&
    /(not significant|non-statistically significant|no significant|do not support|does not support)/i.test(sentence)
  );
}

function sentenceHasAny(sentence, terms) {
  return terms.some(t => sentence.includes(t));
}

// ============================================
// DETECTAR DIRECCIÓN DEL ARTÍCULO
// ============================================

const articlesWithDirection = articles.map(article => {
  const title = normalizeText(article.title || '');
  const abstract = normalizeText(article.abstract || '');
  const conclusion = extractConclusion(abstract);
  const text = `${title}. ${abstract}. ${conclusion}`;

  const exposureTerms = [
    ...(article.matched_exposure || []),
    ...(article.title_exposure_matches || [])
  ].map(normalizeText).filter(Boolean);

  let outcomeTerms = [
    ...(article.matched_outcomes || []),
    ...(article.title_outcome_matches || [])
  ].map(normalizeText).filter(Boolean);

  const isRenalClaim = /(renal|kidney|riñon|rinon|daño renal|kidney damage|renal damage)/i.test(claimText) || claimIsAboutHarm;
  const articleMentionsRenal = /(renal|kidney|riñon|rinon|renal function|kidney function|creatinine|urea|gfr|egfr|blood urea nitrogen|bun)/i.test(text);

  if (isRenalClaim && articleMentionsRenal) {
    outcomeTerms.push('renal function', 'kidney function', 'renal damage', 'kidney damage', 'creatinine', 'urea');
    outcomeTerms = [...new Set(outcomeTerms)];
  }

  const sentences = text
    .split(/(?<=[.!?])\s+/)
    .map(s => normalizeText(s))
    .filter(Boolean);

  const candidateSentences = sentences.filter(sentence => {
    const hasExposure = exposureTerms.some(exp => sentence.includes(exp));
    const hasOutcome = outcomeTerms.some(out => sentence.includes(out));
    return hasExposure || hasOutcome;
  });

  const conclusionSentences = candidateSentences.filter(s =>
    /conclusion|conclude|findings suggest|indicate that|demonstrates that|found that/i.test(s)
  );

  const focusedSentences = conclusionSentences.length > 0 ? conclusionSentences : candidateSentences;
  const focusedText = focusedSentences.length ? focusedSentences.join(' ') : text;

  let hasBenefit = sentenceHasAny(focusedText, benefitTerms) || hasMetricBelowOne(focusedText);
  let hasHarm = sentenceHasAny(focusedText, harmTerms) || hasMetricAboveOne(focusedText);
  let hasNull = sentenceHasAny(focusedText, nullTerms) || hasStrongNullWithRiskMetric(focusedText);
  let hasUncertainty = sentenceHasAny(focusedText, uncertaintyTerms);

  const explicitNullPatterns = [
    /does not induce/i, /do not induce/i, /not induce/i, /no damage/i,
    /does not cause/i, /no adverse effect/i, /did not alter/i, /does not alter/i,
    /not impair/i, /no toxicity/i, /no renal damage/i, /preserved kidney function/i,
    /suggesting preserved kidney function/i
  ];

  if (explicitNullPatterns.some(p => p.test(focusedText))) {
    hasNull = true;
    hasHarm = false;
    hasBenefit = false;
  }

  const isCancerClaim = /cancer|neoplasm|tumor|melanoma|carcinoma/i.test(claimText);

  if (isCancerClaim && !hasHarm && !hasBenefit && !hasNull) {
    if (/(associated with|linked to|relationship between|effect of)/i.test(focusedText)) {
      hasHarm = true;
    }
  }

  if ((claimDirection === 'harmful' || claimIsAboutHarm) && hasBenefit && !hasHarm) {
    if (/(no|not|without|did not|does not)/i.test(focusedText)) {
      hasBenefit = false;
      hasNull = true;
    }
  }

  const strongNullSentences = focusedSentences.filter(s =>
    /(do not support|does not support|did not support|no significant|not associated|no association|not causal|does not induce|no damage|preserved kidney function)/i.test(s)
  );

  if (strongNullSentences.length && !focusedSentences.some(s => !strongNullSentences.includes(s))) {
    hasNull = true;
    hasHarm = false;
    hasBenefit = false;
  }

  // Priorizar beneficio sobre daño para claims de beneficio específico
  let finalHasBenefit = hasBenefit;
  let finalHasHarm = hasHarm;
  let finalHasNull = hasNull;
  let finalHasUncertainty = hasUncertainty;

  if (claimFocusesOnBenefit && hasBenefit && !hasNull && (hasHarm || hasUncertainty)) {
    finalHasHarm = false;
    finalHasNull = false;
    finalHasUncertainty = false;
  }

  let evidence_direction = 'UNCLEAR';
  let direction_confidence = 'LOW';
  let relation_to_claim = 'UNCLEAR';

  if (finalHasBenefit && !finalHasHarm && !finalHasNull) {
    evidence_direction = 'BENEFICIAL_OR_PROTECTIVE';
  } else if (finalHasHarm && !finalHasBenefit && !finalHasNull) {
    evidence_direction = 'HARMFUL_OR_INCREASED_RISK';
  } else if (finalHasNull && !finalHasBenefit && !finalHasHarm) {
    evidence_direction = 'NULL_OR_NO_SIGNIFICANT_ASSOCIATION';
  } else if (finalHasBenefit && finalHasNull && !finalHasHarm) {
    evidence_direction = 'BENEFICIAL_BUT_MIXED_OR_LIMITED';
  } else if (finalHasHarm && finalHasNull && !finalHasBenefit) {
    evidence_direction = 'HARMFUL_BUT_MIXED_OR_LIMITED';
  } else if (finalHasBenefit && finalHasHarm) {
    evidence_direction = 'MIXED_WITHIN_ARTICLE';
  }

  if (article.strong_relation_match && article.has_exposure && article.has_outcome) {
    direction_confidence = hasUncertainty || hasNull ? 'MODERATE' : 'HIGH';
  } else if (article.has_exposure && article.has_outcome) {
    direction_confidence = hasUncertainty || hasNull ? 'LOW' : 'MODERATE';
  }

  const riskMetrics = extractRiskMetrics(focusedText);
  if (riskMetrics.length > 0 && direction_confidence === 'LOW') {
    direction_confidence = 'MODERATE';
  }

  // Mapeo a relation_to_claim
  if (claimDirection === 'beneficial') {
    if (evidence_direction === 'BENEFICIAL_OR_PROTECTIVE' ||
        evidence_direction === 'BENEFICIAL_BUT_MIXED_OR_LIMITED') {
      relation_to_claim = 'SUPPORTS_CLAIM';
    } else if (evidence_direction === 'HARMFUL_OR_INCREASED_RISK' ||
               evidence_direction === 'HARMFUL_BUT_MIXED_OR_LIMITED') {
      relation_to_claim = 'CONTRADICTS_CLAIM';
    } else if (evidence_direction === 'NULL_OR_NO_SIGNIFICANT_ASSOCIATION') {
      relation_to_claim = 'DOES_NOT_SUPPORT_CLAIM';
    }
  }

  if (claimDirection === 'harmful') {
    if (evidence_direction === 'HARMFUL_OR_INCREASED_RISK' ||
        evidence_direction === 'HARMFUL_BUT_MIXED_OR_LIMITED') {
      relation_to_claim = 'SUPPORTS_CLAIM';
    } else if (evidence_direction === 'BENEFICIAL_OR_PROTECTIVE' ||
               evidence_direction === 'BENEFICIAL_BUT_MIXED_OR_LIMITED') {
      relation_to_claim = 'CONTRADICTS_CLAIM';
    } else if (evidence_direction === 'NULL_OR_NO_SIGNIFICANT_ASSOCIATION') {
      relation_to_claim = 'DOES_NOT_SUPPORT_CLAIM';
    }
  }

  if (evidence_direction === 'MIXED_WITHIN_ARTICLE') {
    relation_to_claim = 'MIXED_OR_CONTEXT_DEPENDENT';
  }

  if ((claimDirection === 'harmful' || claimIsAboutHarm) && explicitNullPatterns.some(p => p.test(focusedText))) {
    relation_to_claim = 'CONTRADICTS_CLAIM';
    evidence_direction = 'NULL_OR_NO_SIGNIFICANT_ASSOCIATION';
    direction_confidence = direction_confidence === 'HIGH' ? 'HIGH' : 'MODERATE';
  }

  // Forzar SUPPORTS_CLAIM para claims de beneficio específico con evidencia
  if (claimFocusesOnBenefit && hasBenefit && !hasNull && claimDirection === 'beneficial') {
    relation_to_claim = 'SUPPORTS_CLAIM';
    evidence_direction = 'BENEFICIAL_OR_PROTECTIVE';
    direction_confidence = direction_confidence === 'HIGH' ? 'HIGH' : 'MODERATE';
  }

  article.canonical = article.canonical || {};
  article.canonical.directionality = {
    relation: relation_to_claim,
    evidence_direction,
    confidence: direction_confidence
  };

  const riskMetricsDetected = candidateSentences.flatMap(extractRiskMetrics);

  let finalHasOutcome = article.has_outcome;
  if (isRenalClaim && articleMentionsRenal) {
    finalHasOutcome = true;
  }

  return {
    ...article,
    evidence_direction,
    relation_to_claim,
    direction_confidence,
    has_outcome: finalHasOutcome,
    directionality_flags: {
      has_benefit_language: hasBenefit,
      has_harm_language: hasHarm,
      has_null_language: hasNull,
      has_uncertainty_language: hasUncertainty,
      candidate_sentence_count: candidateSentences.length,
      conclusion_sentence_count: conclusionSentences.length,
      risk_metrics_detected: riskMetricsDetected
    },
    directionality_debug: {
      candidate_sentences: candidateSentences.slice(0, 8),
      conclusion_sentences: conclusionSentences.slice(0, 5),
      supporting_sentences: focusedSentences.filter(s => sentenceHasAny(s, benefitTerms)).slice(0, 5),
      harm_sentences: focusedSentences.filter(s => sentenceHasAny(s, harmTerms)).slice(0, 5),
      null_sentences: focusedSentences.filter(s => sentenceHasAny(s, nullTerms)).slice(0, 5)
    }
  };
});

// ============================================
// RESUMEN DE DIRECTIONALITY
// ============================================

const directionalitySummary = {
  claim_direction: claimDirection,
  claim_focuses_on_benefit: claimFocusesOnBenefit,
  claim_is_about_harm: claimIsAboutHarm,
  supports_claim_count: articlesWithDirection.filter(a => a.relation_to_claim === 'SUPPORTS_CLAIM').length,
  contradicts_claim_count: articlesWithDirection.filter(a => a.relation_to_claim === 'CONTRADICTS_CLAIM').length,
  does_not_support_claim_count: articlesWithDirection.filter(a => a.relation_to_claim === 'DOES_NOT_SUPPORT_CLAIM').length,
  mixed_or_unclear_count: articlesWithDirection.filter(a =>
    ['MIXED_OR_CONTEXT_DEPENDENT', 'UNCLEAR'].includes(a.relation_to_claim)
  ).length,
  metric_supported_count: articlesWithDirection.filter(a =>
    (a.directionality_flags?.risk_metrics_detected || []).some(m =>
      m.ci_crosses_one === false && (m.value > 1.05 || m.value < 0.95)
    )
  ).length,
  note: 'Directionality mejorado: detecta explícitamente "does not induce", "no damage", claims de daño renal, prioriza beneficio sobre daño para claims de beneficio específico, y fuerza CONTRADICTS_CLAIM cuando corresponde.'
};

return [{
  json: {
    ...input,
    articles: articlesWithDirection,
    directionality_summary: directionalitySummary
  }
}];

