    let contradictedOutcome = null;
    const outcomeTerms = [
      'mortality', 'death', 'cancer', 'tumor', 'cardiovascular',
      'diabetes', 'blood pressure', 'weight', 'obesity', 'inflammation'
    ];

    for (const term of outcomeTerms) {
      if (text.includes(term) && claimOutcome.toLowerCase().includes(term)) {
        contradictedOutcome = term;
        break;
      }
    }

    let contradictionType = 'MAGNITUDE_ONLY';
    const causalTerms = ['causes', 'causal', 'prevents', 'protects', 'association', 'associated'];

    for (const term of causalTerms) {
      if (text.includes(term) && claimOutcome.toLowerCase().includes('caus')) {
        contradictionType = 'CAUSALITY_OR_DIRECTION';
        break;
      }
    }

    contradictions.push({
      pmid: article.pmid,
      title: article.title,
      contradicted_outcome: contradictedOutcome,
      contradiction_type: contradictionType,
      evidence_level: article.evidence_level,
      study_design: article.study_design,
      risk_of_bias_estimate: article.risk_of_bias_estimate,
      relevance_score: article.relevance_score
    });
  }
}

const contradictionClusters = {
  total_contradicting: contradictions.length,
  by_outcome: {},
  by_type: { CAUSALITY_OR_DIRECTION: 0, MAGNITUDE_ONLY: 0 },
  details: contradictions
};

for (const c of contradictions) {
  if (c.contradicted_outcome) {
    contradictionClusters.by_outcome[c.contradicted_outcome] = 
      (contradictionClusters.by_outcome[c.contradicted_outcome] || 0) + 1;
  }
  contradictionClusters.by_type[c.contradiction_type]++;
}

return [{
  json: {
    ...input,
    contradiction_clusters: contradictionClusters
  }
}];

const input = $input.first().json;
const articles = input.articles || [];

// ============================================
// CONSENSO CAUSAL EPIDEMIOLÓGICO
// ============================================

const causalConsensus = input.causal_consensus || {};

const reduceObservationalPenalty =
  causalConsensus.reduce_observational_penalty === true;

const causalConsensusStrength =
  causalConsensus.causal_consensus_strength || 'UNKNOWN';

// ============================================
// Función para calcular consenso ponderado
// ============================================

function calculateWeightedConsensus(articles) {
  let weightedSupport = 0;
  let weightedContradict = 0;
  let weightedNull = 0;
  let weightedUnclear = 0;

  for (const article of articles) {
    const finalScore =
      article.final_score ||
      (article.canonical?.deterministic_confidence || 0) * 100 ||
      0;

    switch (article.relation_to_claim) {
      case 'SUPPORTS_CLAIM':
        weightedSupport += finalScore;
        break;
      case 'CONTRADICTS_CLAIM':
        weightedContradict += finalScore;
        break;
      case 'DOES_NOT_SUPPORT_CLAIM':
        weightedNull += finalScore;
        break;
      default:
        weightedUnclear += finalScore;
        break;
    }
  }

  const totalWeighted =
    weightedSupport + weightedContradict + weightedNull + weightedUnclear;

  let dominantDirection = 'UNCLEAR';
  let dominantWeight = 0;

  if (weightedSupport > dominantWeight) {
    dominantWeight = weightedSupport;
    dominantDirection = 'SUPPORTS_CLAIM';
  }

  if (weightedContradict > dominantWeight) {
    dominantWeight = weightedContradict;
    dominantDirection = 'CONTRADICTS_CLAIM';
  }

  if (weightedNull > dominantWeight) {
    dominantWeight = weightedNull;
    dominantDirection = 'DOES_NOT_SUPPORT_CLAIM';
  }

  return {
    weighted_support: weightedSupport,
    weighted_contradict: weightedContradict,
    weighted_null: weightedNull,
    weighted_unclear: weightedUnclear,
    total_weighted: totalWeighted,
    dominant_direction: dominantDirection,
    dominant_weight: dominantWeight,
    dominant_ratio: totalWeighted > 0 ? dominantWeight / totalWeighted : 0
  };
}

// ============================================
// 1. CALCULAR FINAL_SCORE USANDO CANONICAL
// ============================================

const scoredArticles = articles.map(article => {
  const canon = article.canonical || {};

  const adjustedEvidenceWeight = Number(
    canon.study_weight ||
    article.adjusted_evidence_weight ||
    article.evidence_weight ||
    0
  );

  const relevanceScore = Number(
    canon.relevance?.score ||
    article.relevance_score ||
    0
  );

  const temporalWeight = Number(
    canon.temporal?.weight ||
    article.temporal_weight ||
    0
  );

  // ============================================
  // MODIFICADORES DE RELEVANCIA
  // Vienen del nodo "Clasificar Artículos"
  // ============================================

  const relevanceModifiers = article.relevance_modifiers || {};

  const exposureSpecificityPenalty = Number(
    relevanceModifiers.exposure_specificity_penalty || 0
  );

  const claimCentralityScore = Number(
    relevanceModifiers.claim_centrality_score || 0
  );

  const outcomeTierScore = Number(
    relevanceModifiers.outcome_tier_score || 0
  );

const hasExposure =
  article.has_exposure === true ||
  canon.relevance?.has_exposure === true;

const exposureMatchScore = Number(
  article.exposure_match_score ?? 0
);

let exposureMismatchPenalty = 0;

if (exposureMatchScore < 90) {
  exposureMismatchPenalty = 25;
}

const hasOutcome =
  article.has_outcome === true ||
  canon.relevance?.has_outcome === true;

const outcomeMatchScore = Number(
  article.outcome_match_score ?? 0
);

let outcomeMismatchPenalty = 0;

// Si el outcome del artículo no coincide bien con el outcome del claim
if (outcomeMatchScore < 70) {
  outcomeMismatchPenalty = 40;
}

  let hardExposureMismatchPenalty = 0;

  if (!hasExposure && hasOutcome) {
    hardExposureMismatchPenalty = 30;
  }

  // ============================================
  // SEMANTIC CLAIM MATCH SCORE
  // Esto es el nuevo filtro fuerte de relevancia
  // ============================================

  const semanticMatchScore = Number(
    article.semantic_claim_match_score ??
    article.claim_semantic_match_score ??
    canon.relevance?.semantic_claim_match_score ??
    Math.max(
      0,
      Math.min(
        100,
        (relevanceScore * 0.35) +
        claimCentralityScore +
        outcomeTierScore +
        exposureSpecificityPenalty -
        hardExposureMismatchPenalty
      )
    )
  );

  const strongRelationMatch =
  article.strong_relation_match === true ||
  canon.relevance?.strong_relation_match === true;

let semanticGateApplied = 'NONE';
let semanticPenaltyMultiplier = 1;

if (semanticMatchScore === 0) {

  semanticGateApplied = 'VERY_STRONG_PENALTY';
  semanticPenaltyMultiplier = 0.1;

} else if (!strongRelationMatch) {

  semanticGateApplied = 'NO_STRONG_RELATION_PENALTY';
  semanticPenaltyMultiplier = 0.25;

} else if (semanticMatchScore < 10) {

  semanticGateApplied = 'STRONG_PENALTY';
  semanticPenaltyMultiplier = 0.3;

} else if (semanticMatchScore < 20) {

  semanticGateApplied = 'MODERATE_PENALTY';
  semanticPenaltyMultiplier = 0.6;

}

  // ============================================
  // Study bonus
  // ============================================

  let studyBonus = 0;
  const studyType = canon.study_type || article.study_type;

  if (studyType === 'UMBRELLA_REVIEW') studyBonus = 30;
  else if (studyType === 'SYSTEMATIC_REVIEW_META_ANALYSIS') studyBonus = 25;
  else if (studyType === 'META_ANALYSIS') studyBonus = 20;
  else if (studyType === 'SYSTEMATIC_REVIEW') studyBonus = 15;
  else if (studyType === 'RCT_OR_CLINICAL_TRIAL') studyBonus = 10;

  // ============================================
  // Outcome bonus
  // ============================================

  const outcomeBonus =
    canon.outcome_strength ||
    (article.has_hard_outcomes ? 15 : article.has_surrogate_outcomes ? 5 : 0);

  // ============================================
  // Heterogeneity penalty
  // ============================================

  let heterogeneityPenalty = 0;

  if (canon.heterogeneity?.severity === 'HIGH') heterogeneityPenalty = 20;
  else if (canon.heterogeneity?.severity === 'MODERATE') heterogeneityPenalty = 10;
  else if (canon.heterogeneity?.severity === 'LOW') heterogeneityPenalty = 3;

  // ============================================
  // Bias penalty
  // ============================================

  let biasPenalty = 0;
  const biasLevel = canon.risk_of_bias?.level || article.risk_of_bias_estimate;

  if (biasLevel === 'HIGH') biasPenalty = 30;
  else if (biasLevel === 'MODERATE') biasPenalty = 15;

  // ============================================
  // Conflict penalty
  // ============================================

  let conflictPenalty = 0;
  const conflictRisk =
    canon.conflicts?.risk || article.conflict_of_interest_risk;

  if (conflictRisk === 'HIGH') conflictPenalty = 20;
  else if (conflictRisk === 'MODERATE') conflictPenalty = 10;

  // ============================================
  // Causal overstatement penalty
  // ============================================

  let overstatementPenalty = 0;

  if (article.causal_overstatement_severity === 'HIGH') {
    overstatementPenalty = 25;
  } else if (article.causal_overstatement_severity === 'MODERATE_TO_HIGH') {
    overstatementPenalty = 20;
  } else if (article.causal_overstatement_severity === 'MODERATE') {
    overstatementPenalty = 15;
  }

  // ============================================
  // Mechanistic penalty
  // ============================================

  let mechanisticPenalty = 0;

  if (article.evidence_type_classification === 'MECHANISTIC_ONLY') {
    mechanisticPenalty = 40;
  } else if (article.evidence_type_classification === 'MIXED_HUMAN_AND_MECHANISTIC') {
    mechanisticPenalty = 15;
  } else if (article.evidence_type_classification === 'PRECLINICAL_ANIMAL_ONLY') {
    mechanisticPenalty = 50;
  }

  // ============================================
  // Non-human penalty
  // ============================================

  let nonHumanPenalty = 0;

  if (!article.is_human_evidence) {
    nonHumanPenalty = 30;
  }

  // ============================================
  // Recent high-quality bonus
  // ============================================

  const recentHighQualityBonus =
    canon.temporal?.is_recent_high_quality || article.is_recent_high_quality
      ? 10
      : 0;

  // ============================================
  // Causal consensus bonus
  // ============================================

  let causalConsensusBonus = 0;

  if (causalConsensusStrength === 'VERY_STRONG') {
    causalConsensusBonus = 25;
  } else if (causalConsensusStrength === 'STRONG') {
    causalConsensusBonus = 20;
  } else if (causalConsensusStrength === 'MODERATE') {
    causalConsensusBonus = 10;
  } else if (causalConsensusStrength === 'WEAK_TO_MODERATE') {
    causalConsensusBonus = 5;
  }

  // ============================================
  // Ajuste de confidence determinista
  // ============================================

  let deterministicConfidence = canon.deterministic_confidence || 0.5;

  if (reduceObservationalPenalty) {
    deterministicConfidence = Math.min(0.95, deterministicConfidence + 0.15);
  }

  // ============================================
  // CÁLCULO FINAL_SCORE BASE
  // ============================================

const weightedRelevanceScore = Math.min(relevanceScore, 100) * 0.35;

let rawFinalScore =
  adjustedEvidenceWeight +
  weightedRelevanceScore +
  claimCentralityScore +
  outcomeTierScore +
  temporalWeight +
  studyBonus +
  outcomeBonus +
  recentHighQualityBonus +
  causalConsensusBonus +
  exposureSpecificityPenalty -
  hardExposureMismatchPenalty -
  exposureMismatchPenalty -
  outcomeMismatchPenalty -
  biasPenalty -
  conflictPenalty -
  heterogeneityPenalty -
  overstatementPenalty -
  mechanisticPenalty -
  nonHumanPenalty;

  // ============================================
  // APLICAR GATE SEMÁNTICO
  // Aquí está la corrección importante
  // ============================================

let final_score = Math.round((rawFinalScore * semanticPenaltyMultiplier) * 100) / 100;
final_score = Math.max(0, final_score);

  return {
    ...article,
    final_score,
    deterministic_confidence: deterministicConfidence,
    semantic_claim_match_score: semanticMatchScore,
    semantic_gate_applied: semanticGateApplied,
    score_components: {
      raw_final_score: rawFinalScore,
      semantic_claim_match_score: semanticMatchScore,
      semantic_gate_applied: semanticGateApplied,
      semantic_penalty_multiplier: semanticPenaltyMultiplier,

      adjusted_evidence_weight: adjustedEvidenceWeight,
      relevance_score_raw: relevanceScore,
      relevance_score_weighted: relevanceScore * 0.35,
      claim_centrality_score: claimCentralityScore,
      outcome_tier_score: outcomeTierScore,
      exposure_specificity_penalty: exposureSpecificityPenalty,
      hard_exposure_mismatch_penalty: hardExposureMismatchPenalty,
      exposure_mismatch_penalty: exposureMismatchPenalty,
      outcome_mismatch_penalty: outcomeMismatchPenalty,

      temporal_weight: temporalWeight,
      study_bonus: studyBonus,
      outcome_bonus: outcomeBonus,
      recent_high_quality_bonus: recentHighQualityBonus,
      causal_consensus_bonus: causalConsensusBonus,

      bias_penalty: biasPenalty,
      conflict_penalty: conflictPenalty,
      heterogeneity_penalty: heterogeneityPenalty,
      overstatement_penalty: overstatementPenalty,
      mechanistic_penalty: mechanisticPenalty,
      non_human_penalty: nonHumanPenalty,

      causal_consensus_strength: causalConsensusStrength,
      reduce_observational_penalty: reduceObservationalPenalty
    }
  };
});

// ============================================
// 2. ORDENAR POR FINAL_SCORE
// ============================================

const rankedArticles = scoredArticles.sort(
  (a, b) => b.final_score - a.final_score
);

function isRelevantEnough(article) {
  const semantic = Number(article.semantic_claim_match_score || 0);
  const relevance = Number(article.relevance_score || 0);

  const hasExposure =
    article.has_exposure === true ||
    article.canonical?.relevance?.has_exposure === true ||
    (Array.isArray(article.matched_exposure) && article.matched_exposure.length > 0);

  const hasOutcome =
    article.has_outcome === true ||
    article.canonical?.relevance?.has_outcome === true ||
    (Array.isArray(article.matched_outcomes) && article.matched_outcomes.length > 0);

  const strongRelation =
    article.strong_relation_match === true ||
    article.canonical?.relevance?.strong_relation_match === true;

  // Excluir artículos que solo coinciden por outcome, pero no por exposición
  if (!hasExposure && hasOutcome && semantic === 0) {
    return false;
  }

  if (strongRelation) return true;
  if (hasExposure && hasOutcome) return true;
  if (semantic >= 20 && relevance > 0) return true;

  return false;
}

const relevantRankedArticles = rankedArticles.filter(isRelevantEnough);
const rankingPool = relevantRankedArticles;

// ============================================
// 3. SELECCIONAR TOP ARTÍCULOS ESTRATÉGICAMENTE
// ============================================

const topQuality = rankingPool.slice(0, 5);

const topContradictors = rankingPool
  .filter(a => a.relation_to_claim === 'CONTRADICTS_CLAIM')
  .sort((a, b) => b.final_score - a.final_score)
  .slice(0, 3);

const topNullEvidence = rankingPool
  .filter(a => a.relation_to_claim === 'DOES_NOT_SUPPORT_CLAIM')
  .sort((a, b) => b.final_score - a.final_score)
  .slice(0, 3);

const finalArticlesSet = new Map();

[...topQuality, ...topContradictors, ...topNullEvidence].forEach(article => {
  if (!finalArticlesSet.has(article.pmid)) {
    finalArticlesSet.set(article.pmid, article);
  }
});

const finalArticles = Array.from(finalArticlesSet.values()).sort(
  (a, b) => b.final_score - a.final_score
);

// ============================================
// 4. CONSENSO PONDERADO
// ============================================

const weightedConsensus = calculateWeightedConsensus(finalArticles);

let weightedConsensusLevel = 'INSUFFICIENT';

if (weightedConsensus.total_weighted >= 100) {
  if (weightedConsensus.dominant_ratio >= 0.7) {
    weightedConsensusLevel = 'STRONG';
  } else if (weightedConsensus.dominant_ratio >= 0.55) {
    weightedConsensusLevel = 'MODERATE';
  } else {
    weightedConsensusLevel = 'MIXED';
  }
} else if (weightedConsensus.total_weighted >= 30) {
  weightedConsensusLevel = 'WEAK';
}

// ============================================
// 5. OUTPUT
// ============================================

return [
  {
    json: {
      ...input,
      articles: finalArticles,
      all_ranked_articles: rankedArticles,
      weighted_consensus: weightedConsensus,
      weighted_consensus_level: weightedConsensusLevel,
      ranking_summary: {
        top_article: finalArticles[0]
          ? {
              pmid: finalArticles[0].pmid,
              title: finalArticles[0].title,
              study_type:
                finalArticles[0].canonical?.study_type ||
                finalArticles[0].study_type,
              final_score: finalArticles[0].final_score,
              raw_final_score: finalArticles[0].score_components?.raw_final_score,
              semantic_claim_match_score:
                finalArticles[0].semantic_claim_match_score,
              semantic_gate_applied:
                finalArticles[0].semantic_gate_applied,
              deterministic_confidence:
                finalArticles[0].deterministic_confidence,
              relation_to_claim: finalArticles[0].relation_to_claim,
              score_components: finalArticles[0].score_components,
              relevance_modifiers: finalArticles[0].relevance_modifiers || null
            }
          : null,
        total_articles_considered: scoredArticles.length,
        final_articles_selected: finalArticles.length,
        top_quality_count: topQuality.length,
        contradictory_count: topContradictors.length,
        null_evidence_count: topNullEvidence.length,
        causal_consensus_strength: causalConsensusStrength,
        reduce_observational_penalty: reduceObservationalPenalty
      }
    }
  }
];

// Nodo: "Canonical Evidence Object"
