const input = $input.first().json;
const articles = input.articles || [];

// ============================================
// JERARQUÍAS Y PESOS CANÓNICOS
// ============================================

const STUDY_HIERARCHY = {
  'UMBRELLA_REVIEW': 14,
  'SYSTEMATIC_REVIEW_META_ANALYSIS': 12,
  'META_ANALYSIS': 10,
  'SYSTEMATIC_REVIEW': 9,
  'RCT_OR_CLINICAL_TRIAL': 8,
  'OBSERVATIONAL_COHORT': 5,
  'CASE_CONTROL': 3,
  'CROSS_SECTIONAL': 2,
  'UNKNOWN': 1
};

const CAUSAL_HIERARCHY = {
  'INTERVENTIONAL': 8,
  'OBSERVATIONAL_META_ANALYSIS': 5,
  'OBSERVATIONAL_REVIEW': 4,
  'OBSERVATIONAL': 3,
  'PRECLINICAL': 1,
  'UNCLEAR': 0
};

const OUTCOME_STRENGTH = {
  'MORTALITY': 25,
  'MAJOR_CLINICAL_EVENTS': 18,
  'CANCER_INCIDENCE': 18,
  'IMPORTANT_CLINICAL': 14,
  'INTERMEDIATE_CLINICAL': 8,
  'BIOMARKER': 4,
  'MECHANISTIC': 2,
  'UNCLEAR': 0
};

const RISK_OF_BIAS_PENALTY = {
  'HIGH': -0.25,
  'MODERATE': -0.1,
  'LOW': 0
};

const CONFLICT_PENALTY = {
  'HIGH': -0.2,
  'MODERATE': -0.1,
  'LOW': 0
};

// ============================================
// FUNCIONES DE DETECCIÓN
// ============================================

function detectOutcomeCategory(article) {
  const text = `${article.title || ''} ${article.abstract || ''}`.toLowerCase();

  if (/(all-cause mortality|overall mortality|death from any cause)/i.test(text)) {
    return { category: 'MORTALITY', strength: OUTCOME_STRENGTH.MORTALITY };
  }
  if (/(cancer mortality|cardiovascular mortality|mortality|death)/i.test(text)) {
    return { category: 'MORTALITY', strength: OUTCOME_STRENGTH.MORTALITY - 3 };
  }
  if (/(cardiovascular events|myocardial infarction|stroke|hospitalization)/i.test(text)) {
    return { category: 'MAJOR_CLINICAL_EVENTS', strength: OUTCOME_STRENGTH.MAJOR_CLINICAL_EVENTS };
  }
  if (/(cancer|neoplasm|tumor|incidence|melanoma)/i.test(text)) {
    return { category: 'CANCER_INCIDENCE', strength: OUTCOME_STRENGTH.CANCER_INCIDENCE };
  }
  if (/(heart failure|diabetes diagnosis|fracture|dementia|ckd|renal failure)/i.test(text)) {
    return { category: 'IMPORTANT_CLINICAL', strength: OUTCOME_STRENGTH.IMPORTANT_CLINICAL };
  }
  if (/(blood pressure|hypertension|glucose|hba1c|insulin sensitivity)/i.test(text)) {
    return { category: 'INTERMEDIATE_CLINICAL', strength: OUTCOME_STRENGTH.INTERMEDIATE_CLINICAL };
  }
  if (/(cholesterol|ldl|hdl|triglycerides|inflammatory marker|crp|cytokine)/i.test(text)) {
    return { category: 'BIOMARKER', strength: OUTCOME_STRENGTH.BIOMARKER };
  }
  if (/(in vitro|cell culture|animal model|mouse|mice|rat)/i.test(text)) {
    return { category: 'MECHANISTIC', strength: OUTCOME_STRENGTH.MECHANISTIC };
  }

  return { category: 'UNCLEAR', strength: OUTCOME_STRENGTH.UNCLEAR };
}

function detectHeterogeneity(article) {
  const text = `${article.abstract || ''}`.toLowerCase();

  // Intentar extraer I²
  const i2Patterns = [
    /I²\s*=\s*(\d+(?:\.\d+)?)%?/i,
    /I-squared\s*=\s*(\d+(?:\.\d+)?)%?/i,
    /heterogeneity\s+I²\s*=\s*(\d+(?:\.\d+)?)/i
  ];

  let i2 = null;
  for (const pattern of i2Patterns) {
    const match = text.match(pattern);
    if (match) {
      i2 = parseFloat(match[1]);
      break;
    }
  }

  // Detectar mención de heterogeneidad sin valor específico
  const hasHeterogeneityMention = /heterogeneity|i²|i-squared|inconsistent|between-study variability/i.test(text);
  const hasRandomEffects = /random effects|random-effects|random effect model/i.test(text);

  let severity = 'NONE';
  let confidence = 'LOW';

  if (i2 !== null) {
    confidence = 'HIGH';
    if (i2 >= 75) severity = 'HIGH';
    else if (i2 >= 50) severity = 'MODERATE';
    else if (i2 >= 25) severity = 'LOW';
  } else if (hasHeterogeneityMention) {
    severity = 'MODERATE';
    confidence = 'MODERATE';
  } else if (hasRandomEffects) {
    severity = 'LOW';
    confidence = 'MODERATE';
  }

  return { severity, confidence, i2, has_random_effects: hasRandomEffects };
}

function detectDependencyRisk(article, allArticles) {
  // Por ahora, placeholder. Future: detect overlapping cohorts, same authors, same dataset
  return { risk: 'LOW', reason: 'No dependency detection implemented yet' };
}

// ============================================
// CONSTRUCCIÓN DEL OBJETO CANÓNICO
// ============================================

const canonicalArticles = articles.map(article => {
  const studyType = article.study_type || 'UNKNOWN';
  const underlyingType = article.underlying_evidence_type || 'UNCLEAR';

  // Outcome detection
  const outcome = detectOutcomeCategory(article);

  // Heterogeneity detection
  const heterogeneity = detectHeterogeneity(article);

  // Risk of bias
  const riskOfBias = {
    score: article.risk_of_bias_score || 0,
    level: article.risk_of_bias_estimate || 'LOW',
    penalty: RISK_OF_BIAS_PENALTY[article.risk_of_bias_estimate] || 0
  };

  // Conflicts
  const conflicts = {
    risk: article.conflict_of_interest_risk || 'LOW',
    score: article.conflict_score || 0,
    penalty: CONFLICT_PENALTY[article.conflict_of_interest_risk] || 0
  };

  // Temporal
  const temporal = {
    year: article.publication_year,
    weight: article.temporal_weight || 0,
    is_recent_high_quality: article.is_recent_high_quality || false
  };

  // Directionality
  const directionality = {
    relation: article.relation_to_claim || 'UNCLEAR',
    confidence: article.direction_confidence || 'LOW'
  };

  // Relevance
  const relevance = {
    score: article.relevance_score || 0,
    has_exposure: article.has_exposure || false,
    has_outcome: article.has_outcome || false,
    strong_relation_match: article.strong_relation_match || false
  };

  // Calcular baseline confidence (sin ajustes posteriores)
  let baselineConfidence = 0.5;
  if (underlyingType === 'INTERVENTIONAL') baselineConfidence = 0.8;
  else if (underlyingType === 'OBSERVATIONAL_META_ANALYSIS') baselineConfidence = 0.6;
  else if (underlyingType === 'OBSERVATIONAL_REVIEW') baselineConfidence = 0.5;
  else if (underlyingType === 'OBSERVATIONAL') baselineConfidence = 0.4;
  else if (underlyingType === 'PRECLINICAL') baselineConfidence = 0.2;

  // Construir objeto canónico
  const canonical = {
    // Core
    study_type: studyType,
    study_weight: STUDY_HIERARCHY[studyType] || 1,

    underlying_type: underlyingType,
    causal_weight: CAUSAL_HIERARCHY[underlyingType] || 0,

    // Outcomes
    outcome_category: outcome.category,
    outcome_strength: outcome.strength,

    // Risk of bias
    risk_of_bias: riskOfBias,

    // Heterogeneity
    heterogeneity: heterogeneity,

    // Conflicts
    conflicts: conflicts,

    // Temporal
    temporal: temporal,

    // Directionality
    directionality: directionality,

    // Relevance
    relevance: relevance,

    // Confidence (deterministic, antes de ajustes)
    baseline_confidence: baselineConfidence,

    // Score final (preservar si ya existe)
    final_score: article.final_score || null
  };

  // Calcular deterministic_confidence
  let deterministicConfidence = baselineConfidence;
  deterministicConfidence += riskOfBias.penalty;
  deterministicConfidence += conflicts.penalty;
  deterministicConfidence += (outcome.strength / 100); // Normalizar a 0-0.25
  deterministicConfidence += (heterogeneity.severity === 'HIGH' ? -0.2 :
                              heterogeneity.severity === 'MODERATE' ? -0.1 : 0);
  deterministicConfidence += (temporal.weight / 10);

  // Clamp entre 0.05 y 0.95
  deterministicConfidence = Math.min(0.95, Math.max(0.05, deterministicConfidence));
  canonical.deterministic_confidence = deterministicConfidence;

  return {
    ...article,
    canonical: canonical
  };
});

// ============================================
// OUTPUT
// ============================================

return [{
  json: {
    ...input,
    articles: canonicalArticles,
    canonical_version: '1.0.0',
    note: 'Canonical Evidence Object aplicado. Usar article.canonical para toda lógica posterior.'
  }
}];

// ============================================
// EVALUAR CONSENSO CAUSAL
// Usa los Bradford Hill Signals para modular
// la penalización observacional y construir
// el veredicto preliminar de causalidad.
// ============================================

const input = $input.first().json;
const articles = input.articles || [];
const cc = input.causal_consensus || {};

const strength = cc.causal_consensus_strength || 'UNKNOWN';
const reducepenalty = cc.reduce_observational_penalty || false;
const isNoRct = cc.is_no_rct_domain || false;
const bhRatio = cc.bradford_hill_ratio || 0;
const criteria = cc.criteria || {};

// ============================================
// CALCULAR PENALIZACIÓN OBSERVACIONAL AJUSTADA
// Sin Bradford Hill: observacional siempre penaliza
// Con Bradford Hill fuerte: penalización reducida o eliminada
// ============================================

function getObservationalPenalty(article) {
  const uType = article.underlying_evidence_type || '';
  const isObs = ['OBSERVATIONAL', 'OBSERVATIONAL_REVIEW',
    'OBSERVATIONAL_META_ANALYSIS'].includes(uType);

  if (!isObs) return 0;

  // Si tenemos señal causal fuerte, no penalizar
  if (reducepenalty && ['VERY_STRONG', 'STRONG'].includes(strength)) return 0;

  // Si tenemos señal moderada, penalizar menos
  if (reducepenalty && strength === 'MODERATE') return -5;

  // Penalización normal
  return -10;
}

// ============================================
// AJUSTAR final_score DE CADA ARTÍCULO
// ============================================

const adjustedArticles = articles.map(article => {
  const originalScore = article.final_score || 0;
  const penalty = getObservationalPenalty(article);
  const adjustedScore = Math.max(0, originalScore + penalty);

  return {
    ...article,
    final_score_original: originalScore,
    observational_penalty_applied: penalty,
    final_score: adjustedScore,
    causal_adjustment_note: penalty !== 0
      ? `Penalización observacional: ${penalty} (Bradford Hill ${bhRatio}%)`
      : penalty === 0 && (article.underlying_evidence_type || '').includes('OBSERVATIONAL')
        ? `Penalización observacional eliminada por Bradford Hill ${strength}`
        : ''
  };
});

// ============================================
// CONSTRUIR SCIENTIFIC_CONTEXT con BH signals
// ============================================

const bh = criteria;

const scientific_context = {
  // Causalidad
  causal_claim_detected: input.tiene_causalidad || false,
  causal_consensus_strength: strength,
  is_no_rct_domain: isNoRct,
  bradford_hill_ratio: bhRatio,
  reduce_observational_penalty: reducepenalty,

  // Señales Bradford Hill individuales
  bradford_hill_signals: {
    strength_of_association: bh.strength_of_association || 'UNKNOWN',
    consistency_across_studies: bh.consistency_across_studies || 'UNKNOWN',
    temporality_established: bh.temporality_established || 'UNKNOWN',
    dose_response_detected: bh.dose_response_detected || 'NOT_DETECTED',
    biological_plausibility: bh.biological_plausibility || 'UNKNOWN',
    coherence_with_biology: bh.coherence_with_biology || 'UNKNOWN',
    experimental_evidence: bh.experimental_evidence || 'NONE',
    specificity_detected: bh.specificity_detected || false,
    analogy_support: bh.analogy_support || 'WEAK'
  },

  // Advertencias epistémicas para Gemini
  epistemic_notes: buildEpistemicNotes(strength, isNoRct, bhRatio, criteria),

  // Riesgos de interpretación
  possible_residual_confounding: articles.some(a =>
    (a.risk_of_bias_flags || []).includes('confounding_risk')),
  possible_reverse_causality: false,
  interpretation_risk: strength === 'UNKNOWN' || bhRatio < 25
    ? 'HIGH — evidencia insuficiente para inferencia causal'
    : reducepenalty
      ? 'LOW — dominio sin RCT, Bradford Hill criteria met'
      : 'MODERATE — evidencia observacional, causalidad no confirmada experimentalmente'
};

function buildEpistemicNotes(strength, isNoRct, bhRatio, criteria) {
  const notes = [];

  if (isNoRct) {
    notes.push('DOMINIO SIN RCT: La ausencia de RCTs NO es evidencia de causalidad incierta en este dominio. Los RCTs son éticamente imposibles para carcinógenos, tóxicos y radiación.');
  }

  if (['VERY_STRONG', 'STRONG'].includes(strength)) {
    notes.push(`CAUSALIDAD EPIDEMIOLÓGICA: Bradford Hill score ${bhRatio}%. El consenso causal se basa en epidemiología, no en RCTs. Este es el estándar epistémico correcto para este tipo de exposición.`);
  }

  if (criteria.dose_response_detected && criteria.dose_response_detected !== 'NOT_DETECTED') {
    notes.push(`GRADIENTE DOSIS-RESPUESTA detectado (${criteria.dose_response_detected}): Uno de los criterios más fuertes para inferencia causal epidemiológica.`);
  }

  if (criteria.biological_plausibility === 'VERY_HIGH') {
    notes.push('PLAUSIBILIDAD BIOLÓGICA MUY ALTA: Mecanismo molecular específico identificado (ej: mutaciones UV signature, CPD, p53). Esto eleva sustancialmente la inferencia causal.');
  }

  if (criteria.consistency_across_studies === 'HIGH') {
    notes.push('CONSISTENCIA ALTA: Resultados replicados en múltiples estudios y poblaciones. Reduce probabilidad de confounding como explicación alternativa.');
  }

  if (criteria.coherence_with_biology === 'HIGH' || criteria.iarc_who_override) {
    notes.push('COHERENCIA CON CONSENSO ESTABLECIDO: IARC/WHO clasificación detectada. El consenso científico institucional respalda la relación causal.');
  }

  if (notes.length === 0) {
    notes.push('Señales Bradford Hill insuficientes. Evaluar con cautela la inferencia causal.');
  }

  return notes;
}

// ============================================
// INSTRUCCIÓN ESPECIAL PARA GEMINI
// Le dice explícitamente cómo usar estos datos
// ============================================

const geminiCausalInstruction = buildGeminiInstruction(strength, isNoRct, bhRatio);

function buildGeminiInstruction(strength, isNoRct, bhRatio) {
  if (['VERY_STRONG', 'STRONG'].includes(strength) && isNoRct) {
    return `INSTRUCCIÓN CAUSAL: Este claim pertenece a un dominio donde los RCTs son éticamente imposibles (carcinógenos, tóxicos, radiación). El Bradford Hill score es ${bhRatio}%. NO penalices la ausencia de RCTs. La evidencia observacional consistente con múltiples criterios Bradford Hill MET es el estándar epistémico correcto. Si el claim dice que algo es "peligroso" o "aumenta el riesgo", y la evidencia epidemiológica es consistente con Bradford Hill criteria, el veredicto apropiado es PARCIALMENTE_CIERTO o VERDADERO con matices de balance riesgo-beneficio, NO EVIDENCIA_INSUFICIENTE ni EXAGERADO por falta de RCTs.`;
  }

  if (strength === 'MODERATE' && isNoRct) {
    return `INSTRUCCIÓN CAUSAL: Dominio sin RCT posible. Bradford Hill score moderado (${bhRatio}%). Evalúa la causalidad con criterios epidemiológicos, no clínicos. La ausencia de RCTs no implica evidencia insuficiente en este contexto.`;
  }

  if (['VERY_STRONG', 'STRONG'].includes(strength) && !isNoRct) {
    return `INSTRUCCIÓN CAUSAL: Bradford Hill score alto (${bhRatio}%). Hay señales fuertes de causalidad epidemiológica aunque parte de la evidencia sea observacional.`;
  }

  return '';
}

console.log('=== EVALUAR CONSENSO CAUSAL ===');
console.log('causal_consensus_strength:', strength);
console.log('reduce_observational_penalty:', reducepenalty);
console.log('is_no_rct_domain:', isNoRct);
console.log('bradford_hill_ratio:', bhRatio + '%');
console.log('gemini_instruction:', geminiCausalInstruction ? 'SET' : 'EMPTY');

return [{
  json: {
    ...input,
    articles: adjustedArticles,
    scientific_context,
    gemini_causal_instruction: geminiCausalInstruction
  }
}];

const input = $input.first().json;

if (input.source !== 'benchmark' || !input.benchmark_id) {
  return [{ json: input }];
}

console.log(JSON.stringify(input, null, 2));
const actualVerdict = input.actual_verdict || input.veredicto || null;
const actualConfidence = input.actual_confidence || input.confidence_level || null;
const actualConsensus = input.actual_consensus || input.consensus_level || null;
const actualReasoning =
  input.actual_reasoning ||
  input.analisis_detallado ||
  input.explicacion_corta ||
  '';

const failReasons = [];

if (input.expected_verdict && input.expected_verdict !== actualVerdict) {
  failReasons.push(`Veredicto esperado ${input.expected_verdict}, recibido ${actualVerdict}`);
}

if (input.expected_confidence && input.expected_confidence !== actualConfidence) {
  failReasons.push(`Confidence esperada ${input.expected_confidence}, recibida ${actualConfidence}`);
}

if (input.expected_consensus && input.expected_consensus !== actualConsensus) {
  failReasons.push(`Consensus esperado ${input.expected_consensus}, recibido ${actualConsensus}`);
}

return [{
  json: {
    ...input,
    benchmark_update: {
      id: input.benchmark_id,
      actual_verdict: actualVerdict,
      actual_confidence: actualConfidence,
      actual_consensus: actualConsensus,
      actual_reasoning: String(actualReasoning).slice(0, 5000),
      prompt_version: input.pipeline_meta?.prompt_version || null,
      ranking_version: input.pipeline_meta?.ranking_version || null,
      causal_model_version: input.pipeline_meta?.causal_model_version || null,
      retrieval_version: input.pipeline_meta?.retrieval_version || null,
      fail_detected: failReasons.length > 0,
      fail_reason: failReasons.join(' | '),
      execution_status: failReasons.length > 0
      ? 'error'
      : 'success',
      status: 'tested',
      updated_at: new Date().toISOString()
    }
  }
}];

// ============================================
// CONSTRUIR BRADFORD HILL SIGNALS
// Detecta los 9 criterios de Bradford Hill
// a partir del texto de abstracts + claim.
// Diseñado para claims etiológicos donde
// NO existen RCTs posibles (carcinógenos,
// tóxicos, radiación, contaminación).
// ============================================

const input = $input.first().json;
const articles = input.articles || [];
const claim = (input.original_claim || '').toLowerCase();
const claimLimpio = (input.claim_limpio || '').toLowerCase();

// Texto completo para análisis: claim + todos los abstracts + títulos
const allText = [
  claim,
  claimLimpio,
  ...articles.map(a => `${a.title || ''} ${a.abstract || ''}`)
].join(' ').toLowerCase();

// ============================================
// DOMINIOS SIN RCT POSIBLE
// En estos dominios la evidencia observacional
// consistente ES la mejor evidencia disponible.
// ============================================

const NO_RCT_DOMAINS = {
  uv_radiation: /(ultraviolet|uv radiation|uv exposure|sun exposure|solar radiation|sunburn|tanning|sunlight|photodamage|photoaging|uva|uvb)/i.test(allText),
  tobacco: /(tobacco|smoking|cigarette|nicotine|passive smoking|second.?hand smoke)/i.test(allText),
  asbestos: /(asbestos|mesothelioma|chrysotile|crocidolite)/i.test(allText),
  air_pollution: /(air pollution|particulate matter|pm2\.?5|pm10|nitrogen dioxide|ozone exposure)/i.test(allText),
  alcohol_carcinogen: /(alcohol.*cancer|ethanol.*carcinogen|acetaldehyde)/i.test(allText),
  radiation_ionizing: /(ionizing radiation|x.?ray.*cancer|gamma radiation|nuclear|radon)/i.test(allText),
  occupational_exposure: /(occupational exposure|workplace.*cancer|industrial.*carcinogen)/i.test(allText),
  dietary_pattern: /(dietary pattern|diet.*cancer|red meat.*cancer|processed meat)/i.test(allText)
};

const isNoRctDomain = Object.values(NO_RCT_DOMAINS).some(Boolean);
const detectedDomains = Object.entries(NO_RCT_DOMAINS)
  .filter(([, v]) => v)
  .map(([k]) => k);

// ============================================
// CRITERIO 1: FUERZA DE ASOCIACIÓN
// Busca magnitudes de efecto reportadas
// ============================================

const strengthSignals = {
  strong_rr: /(relative risk|risk ratio|hazard ratio|odds ratio)[^.]*[2-9]\.\d|[1-9][0-9]\.\d/i.test(allText),
  very_strong: /(strongly associated|strong association|markedly increased|substantially increased|several.?fold|tenfold|fivefold|threefold)/i.test(allText),
  moderate: /(moderately associated|moderate association|increased risk|elevated risk|higher risk)/i.test(allText),
  any_association: /(associated with|association between|linked to|related to|correlated with)/i.test(allText)
};

const strength_of_association =
  strengthSignals.strong_rr || strengthSignals.very_strong ? 'STRONG' :
  strengthSignals.moderate ? 'MODERATE' :
  strengthSignals.any_association ? 'WEAK' : 'UNKNOWN';

// ============================================
// CRITERIO 2: CONSISTENCIA
// Resultados reproducibles en distintos estudios
// ============================================

const consistencySignals = {
  multiple_studies: /(multiple studies|several studies|many studies|numerous studies|across studies|various studies)/i.test(allText),
  systematic_review: /(systematic review|meta.?analysis|pooled analysis|combined analysis)/i.test(allText),
  consistent_results: /(consistent|consistently|reproducible|replicated|similar findings|convergent)/i.test(allText),
  different_populations: /(different populations|various countries|international|multicenter|multi.?country|diverse populations)/i.test(allText),
  conflicting: /(conflicting|inconsistent|contradictory|mixed results|heterogeneous results)/i.test(allText)
};

const consistency_across_studies =
  (consistencySignals.systematic_review && consistencySignals.consistent_results) ? 'HIGH' :
  (consistencySignals.multiple_studies && consistencySignals.consistent_results) ? 'MODERATE' :
  (consistencySignals.any_association && !consistencySignals.conflicting) ? 'LOW' :
  consistencySignals.conflicting ? 'CONFLICTING' : 'UNKNOWN';

// ============================================
// CRITERIO 3: ESPECIFICIDAD
// La exposición se asocia a outcome específico
// (menos relevante en claims generales)
// ============================================

const specificitySignals = {
  specific_cancer: /(melanoma|basal cell carcinoma|squamous cell carcinoma|specific cancer|particular type)/i.test(allText),
  specific_mechanism: /(specific.*mechanism|particular.*pathway|specific.*mutation|uv signature|cpd|cyclobutane)/i.test(allText),
  dose_specific: /(specific dose|threshold|minimum.*exposure|critical.*exposure)/i.test(allText)
};

const specificity_detected =
  specificitySignals.specific_cancer ||
  specificitySignals.specific_mechanism ||
  specificitySignals.dose_specific;

// ============================================
// CRITERIO 4: TEMPORALIDAD
// La causa precede al efecto
// ============================================

const temporalitySignals = {
  prospective: /(prospective|cohort.*follow.?up|longitudinal|followed.*years|follow.?up.*years)/i.test(allText),
  latency: /(latency|latency period|years.*develop|develop.*after|lag.*time|induction period)/i.test(allText),
  temporal: /(temporal|time.*exposure|exposure.*preceded|prior.*exposure|early.*exposure)/i.test(allText),
  case_control_temporal: /(case.?control|exposure.*before|past.*exposure|history.*exposure)/i.test(allText)
};

const temporality_established =
  (temporalitySignals.prospective && temporalitySignals.latency) ? 'STRONG' :
  (temporalitySignals.prospective || temporalitySignals.latency) ? 'MODERATE' :
  (temporalitySignals.temporal || temporalitySignals.case_control_temporal) ? 'WEAK' : 'UNKNOWN';

// ============================================
// CRITERIO 5: GRADIENTE BIOLÓGICO (DOSIS-RESPUESTA)
// Mayor exposición → mayor efecto
// ============================================

const doseResponseSignals = {
  explicit: /(dose.?response|dose response relationship|gradient|increasing.*risk|risk.*increases|cumulative.*dose)/i.test(allText),
  quantified: /(per.*unit.*increase|per.*hour|per.*year|per.*pack|per.*mgy|per.*sievert)/i.test(allText),
  cumulative: /(cumulative.*exposure|lifetime.*exposure|total.*exposure|years.*exposure|pack.?year)/i.test(allText),
  threshold: /(threshold|minimum.*dose|safe.*level|no.*effect.*level)/i.test(allText)
};

const dose_response_detected =
  (doseResponseSignals.explicit && doseResponseSignals.quantified) ? 'STRONG' :
  (doseResponseSignals.explicit || doseResponseSignals.cumulative) ? 'MODERATE' :
  doseResponseSignals.threshold ? 'WEAK' : 'NOT_DETECTED';

// ============================================
// CRITERIO 6: PLAUSIBILIDAD BIOLÓGICA
// Mecanismo biológico conocido
// ============================================

const plausibilitySignals = {
  dna_damage: /(dna damage|dna repair|mutagenesis|mutation|genotoxic|strand break)/i.test(allText),
  uv_specific_mechanism: /(cyclobutane|cpd|6.?4 photoproduct|uv signature|p53.*mutation|braf.*mutation.*uv|pyrimidine dimer)/i.test(allText),
  oxidative: /(oxidative stress|reactive oxygen|ros|free radical|antioxidant)/i.test(allText),
  carcinogenesis: /(carcinogenesis|tumor.*initiation|tumor.*promotion|oncogene|tumor suppressor)/i.test(allText),
  immunosuppression: /(immunosuppression|immune.*suppression|immune.*evasion|immune.*surveillance)/i.test(allText),
  general_mechanism: /(mechanism|pathway|biological.*basis|plausible|biologically)/i.test(allText)
};

const biological_plausibility =
  (plausibilitySignals.uv_specific_mechanism || plausibilitySignals.dna_damage) &&
  plausibilitySignals.carcinogenesis ? 'VERY_HIGH' :
  (plausibilitySignals.dna_damage || plausibilitySignals.carcinogenesis) ? 'HIGH' :
  (plausibilitySignals.oxidative || plausibilitySignals.general_mechanism) ? 'MODERATE' :
  plausibilitySignals.general_mechanism ? 'LOW' : 'UNKNOWN';

// ============================================
// CRITERIO 7: COHERENCIA
// No contradice conocimiento biológico establecido
// ============================================

const coherenceSignals = {
  established_consensus: /(well established|well-established|known.*carcinogen|established.*risk|consensus.*that|generally accepted|widely accepted)/i.test(allText),
  iarc_who: /(iarc|international agency.*research.*cancer|who.*classification|group 1 carcinogen|group 2a|world health organization)/i.test(allText),
  animal_support: /(animal.*model|mouse.*model|in vivo|experimental.*model|animal.*study.*support)/i.test(allText),
  no_contradiction: !/(contradicts.*established|against.*consensus|challenges.*dogma)/i.test(allText)
};

const coherence_with_biology =
  (coherenceSignals.established_consensus || coherenceSignals.iarc_who) ? 'HIGH' :
  (coherenceSignals.animal_support && coherenceSignals.no_contradiction) ? 'MODERATE' :
  coherenceSignals.no_contradiction ? 'LOW' : 'CONTRADICTS';

// ============================================
// CRITERIO 8: EVIDENCIA EXPERIMENTAL
// Experimentos naturales, estudios de intervención
// ============================================

const experimentalSignals = {
  natural_experiment: /(natural experiment|ozone depletion|latitude.*gradient|altitude.*gradient|seasonal.*variation)/i.test(allText),
  intervention: /(sunscreen.*reduce|sunscreen.*prevent|sun.*protection.*reduce|photoprotection.*reduce)/i.test(allText),
  cessation: /(cessation|quit.*smoking|stop.*exposure|reduction.*exposure.*decrease)/i.test(allText),
  rct: /(randomized|randomised|rct|clinical trial|controlled trial)/i.test(allText)
};

const experimental_evidence =
  experimentalSignals.rct ? 'RCT_AVAILABLE' :
  (experimentalSignals.intervention || experimentalSignals.cessation) ? 'INTERVENTION_EVIDENCE' :
  experimentalSignals.natural_experiment ? 'NATURAL_EXPERIMENT' : 'NONE';

// ============================================
// CRITERIO 9: ANALOGÍA
// Otras exposiciones similares con causalidad establecida
// ============================================

const analogySignals = {
  other_carcinogens: /(similar.*carcinogen|analogous.*exposure|like.*tobacco|as.*asbestos|ionizing.*radiation.*carcinogen)/i.test(allText),
  other_uv_effects: /(cataract.*uv|immune.*suppression.*uv|vitamin d.*uv|erythema.*uv)/i.test(allText)
};

const analogy_support =
  analogySignals.other_carcinogens ? 'STRONG' :
  analogySignals.other_uv_effects ? 'MODERATE' : 'WEAK';

// ============================================
// SCORE BRADFORD HILL TOTAL
// Ponderado: los criterios más importantes
// reciben mayor peso
// ============================================

const criteriaWeights = {
  strength:      { value: strength_of_association !== 'UNKNOWN' && strength_of_association !== 'WEAK', weight: 2 },
  consistency:   { value: ['HIGH', 'MODERATE'].includes(consistency_across_studies), weight: 3 },
  temporality:   { value: ['STRONG', 'MODERATE'].includes(temporality_established), weight: 3 },
  dose_response: { value: ['STRONG', 'MODERATE'].includes(dose_response_detected), weight: 2 },
  plausibility:  { value: ['VERY_HIGH', 'HIGH', 'MODERATE'].includes(biological_plausibility), weight: 2 },
  coherence:     { value: ['HIGH', 'MODERATE'].includes(coherence_with_biology), weight: 2 },
  experiment:    { value: experimental_evidence !== 'NONE', weight: 2 },
  specificity:   { value: specificity_detected, weight: 1 },
  analogy:       { value: analogy_support !== 'WEAK', weight: 1 }
};

let weightedScore = 0;
let maxScore = 0;
const detectedCriteria = [];

for (const [criterion, { value, weight }] of Object.entries(criteriaWeights)) {
  maxScore += weight;
  if (value) {
    weightedScore += weight;
    detectedCriteria.push(criterion);
  }
}

const bhRatio = weightedScore / maxScore;

// ============================================
// CAUSAL CONSENSUS STRENGTH FINAL
// Combina Bradford Hill score + dominio sin RCT
// ============================================

let causal_consensus_strength;
let causal_consensus_reason;
let reduce_observational_penalty;

if (isNoRctDomain && bhRatio >= 0.65) {
  causal_consensus_strength = 'VERY_STRONG';
  causal_consensus_reason = `Dominio sin RCT posible (${detectedDomains.join(', ')}). Bradford Hill score ${Math.round(bhRatio * 100)}% (${weightedScore}/${maxScore}). Criterios detectados: ${detectedCriteria.join(', ')}. La evidencia observacional consistente es el estándar epistémico aplicable.`;
  reduce_observational_penalty = true;
} else if (isNoRctDomain && bhRatio >= 0.45) {
  causal_consensus_strength = 'STRONG';
  causal_consensus_reason = `Dominio sin RCT posible (${detectedDomains.join(', ')}). Bradford Hill score ${Math.round(bhRatio * 100)}% (${weightedScore}/${maxScore}). Criterios detectados: ${detectedCriteria.join(', ')}.`;
  reduce_observational_penalty = true;
} else if (bhRatio >= 0.65) {
  causal_consensus_strength = 'STRONG';
  causal_consensus_reason = `Bradford Hill score alto: ${Math.round(bhRatio * 100)}% (${weightedScore}/${maxScore}). Criterios detectados: ${detectedCriteria.join(', ')}.`;
  reduce_observational_penalty = false;
} else if (bhRatio >= 0.45) {
  causal_consensus_strength = 'MODERATE';
  causal_consensus_reason = `Bradford Hill score moderado: ${Math.round(bhRatio * 100)}% (${weightedScore}/${maxScore}). Criterios detectados: ${detectedCriteria.join(', ')}.`;
  reduce_observational_penalty = false;
} else if (bhRatio >= 0.25) {
  causal_consensus_strength = 'WEAK';
  causal_consensus_reason = `Bradford Hill score bajo: ${Math.round(bhRatio * 100)}% (${weightedScore}/${maxScore}). Pocos criterios detectados: ${detectedCriteria.join(', ') || 'ninguno'}.`;
  reduce_observational_penalty = false;
} else {
  causal_consensus_strength = 'UNKNOWN';
  causal_consensus_reason = 'Señales insuficientes para evaluar causalidad epidemiológica.';
  reduce_observational_penalty = false;
}

// ============================================
// OVERRIDE: IARC/WHO establecido
// Si la OMS/IARC clasifica explícitamente,
