const input = $input.first().json;

function isRelevantEnough(article) {
  const semantic = Number(article.semantic_claim_match_score || 0);
  const relevance = Number(article.relevance_score || 0);

  const hasExposure =
    article.has_exposure === true ||
    article.canonical?.relevance?.has_exposure === true ||
    (Array.isArray(article.matched_exposure) && article.matched_exposure.length > 0);

  const hasOutcome =
    article.has_outcome === true ||
    article.canonical?.relevance?.has_outcome === true ||
    (Array.isArray(article.matched_outcomes) && article.matched_outcomes.length > 0);

  const strongRelation =
    article.strong_relation_match === true ||
    article.canonical?.relevance?.strong_relation_match === true;

  if (!hasExposure && hasOutcome && semantic === 0) {
    return false;
  }

  if (strongRelation) return true;
  if (hasExposure && hasOutcome) return true;
  if (semantic >= 20 && relevance > 0) return true;

  return false;
}

const cleanArticles = (input.articles || []).filter(isRelevantEnough);

const articles = cleanArticles
  .sort((a, b) => (b.final_score || 0) - (a.final_score || 0))
  .slice(0, 6)
  .map(a => ({
    pmid:                    a.pmid,
    title:                   a.title,
    publication_year:        a.publication_year,
    journal:                 a.journal,
    url:                     a.url,
    study_type:              a.study_type,
    underlying_evidence_type: a.underlying_evidence_type,
    evidence_weight:         a.adjusted_evidence_weight ?? a.evidence_weight,
    final_score:             a.final_score,
    has_hard_outcomes:       a.has_hard_outcomes,
    relation_to_claim:       a.relation_to_claim,
    direction_confidence:    a.direction_confidence,
    risk_of_bias_estimate:   a.risk_of_bias_estimate,
    conflict_of_interest_risk: a.conflict_of_interest_risk,
    causal_overstatement_detected: a.causal_overstatement_detected,
    observational_penalty_applied: a.observational_penalty_applied ?? null,
    abstract:                a.abstract
  }));

return [{
  json: {
    ...input,
    ai_evidence_context: articles
  }
}];

const input = $input.first().json;
const articles = input.articles || [];

const topArticles = [...articles]
  .sort((a, b) => (b.final_score || 0) - (a.final_score || 0))
  .slice(0, 6);

const relevanceScores = topArticles
  .map(a => Number(a.relevance_score ?? 0))
  .filter(n => Number.isFinite(n));

const avgRelevanceScore = relevanceScores.length
  ? relevanceScores.reduce((a, b) => a + b, 0) / relevanceScores.length
  : 0;

const strongMatchCount = topArticles.filter(a =>
  a.strong_relation_match === true ||
  a.canonical?.relevance?.strong_relation_match === true
).length;

const exposureMatchCount = topArticles.filter(a =>
  a.has_exposure === true ||
  a.canonical?.relevance?.has_exposure === true ||
  (Array.isArray(a.matched_exposure) && a.matched_exposure.length > 0)
).length;

const outcomeMatchCount = topArticles.filter(a =>
  a.has_outcome === true ||
  a.canonical?.relevance?.has_outcome === true ||
  (Array.isArray(a.matched_outcomes) && a.matched_outcomes.length > 0)
).length;

const hasSystematicReview = topArticles.some(a =>
  ['SYSTEMATIC_REVIEW', 'SYSTEMATIC_REVIEW_META_ANALYSIS', 'META_ANALYSIS', 'UMBRELLA_REVIEW']
    .includes(a.study_type)
);

const currentYear = new Date().getFullYear();

const hasRecentEvidence = topArticles.some(a => {
  const year = Number(a.publication_year || String(a.pubdate || '').match(/\d{4}/)?.[0]);
  return Number.isFinite(year) && year >= currentYear - 5;
});

const outcomeCoverage = [
  ...new Set(
    topArticles.flatMap(a => [
      ...(a.matched_outcomes || []),
      a.canonical?.outcome_category
    ]).filter(Boolean)
  )
];

const exposureCoverage = [
  ...new Set(
    topArticles.flatMap(a => [
      ...(a.matched_exposure || []),
      ...(a.title_exposure_matches || []),
      a.canonical?.exposure_category
    ]).filter(Boolean)
  )
];

const missingDimensions = [];

if (!articles.length) {
  missingDimensions.push('NO_ARTICLES_RETRIEVED');
}

if (topArticles.length < 3) {
  missingDimensions.push('LOW_ARTICLE_COUNT');
}

if (exposureMatchCount === 0) {
  missingDimensions.push('EXPOSURE_NOT_CLEARLY_COVERED');
}

if (outcomeMatchCount === 0) {
  missingDimensions.push('OUTCOME_NOT_CLEARLY_COVERED');
}

if (strongMatchCount === 0) {
  missingDimensions.push('NO_STRONG_EXPOSURE_OUTCOME_MATCH');
}

if (!hasSystematicReview) {
  missingDimensions.push('NO_SYSTEMATIC_REVIEW_OR_META_ANALYSIS_IN_TOP_RESULTS');
}

if (!hasRecentEvidence) {
  missingDimensions.push('NO_RECENT_EVIDENCE_IN_TOP_RESULTS');
}

const possibleQueryBias =
  exposureMatchCount === 0 ||
  outcomeMatchCount === 0 ||
  (avgRelevanceScore < 30 && strongMatchCount === 0);

let coverageQuality = 'HIGH';

if (!articles.length || exposureMatchCount === 0 || outcomeMatchCount === 0) {
  coverageQuality = 'INSUFFICIENT';
} else if (strongMatchCount === 0 || avgRelevanceScore < 35 || possibleQueryBias) {
  coverageQuality = 'LOW';
} else if (avgRelevanceScore < 55 || strongMatchCount < 2) {
  coverageQuality = 'MODERATE';
}

let retrievalConfidence = 'HIGH';

if (coverageQuality === 'INSUFFICIENT' || coverageQuality === 'LOW') {
  retrievalConfidence = 'LOW';
} else if (coverageQuality === 'MODERATE') {
  retrievalConfidence = 'MODERATE';
}

const gemini_instruction =
  coverageQuality === 'INSUFFICIENT'
    ? 'La recuperación de evidencia parece insuficiente: baja la confianza y evita conclusiones fuertes.'
    : coverageQuality === 'LOW'
      ? 'La cobertura de la búsqueda parece débil o sesgada: interpreta la evidencia con cautela y baja confidence_level si procede.'
      : coverageQuality === 'MODERATE'
        ? 'La cobertura de la búsqueda es moderada: permite una conclusión, pero reconoce posibles limitaciones de recuperación.'
        : 'La cobertura de la búsqueda parece adecuada.';

return [{
  json: {
    ...input,
    retrieval_coverage: {
      coverage_quality: coverageQuality,
      avg_relevance_score: Math.round(avgRelevanceScore),
      strong_match_count: strongMatchCount,
      exposure_match_count: exposureMatchCount,
      outcome_match_count: outcomeMatchCount,
      has_systematic_review: hasSystematicReview,
      has_recent_evidence: hasRecentEvidence,
      outcome_coverage: outcomeCoverage,
      exposure_coverage: exposureCoverage,
      missing_dimensions: missingDimensions,
      possible_query_bias: possibleQueryBias,
      retrieval_confidence: retrievalConfidence,
      articles_considered: topArticles.length,
      gemini_instruction
    }
  }
}];

