  /(sugar|azucar|glucose|fructose).*(cancer|tumor)/i.test(claim) ||
  /(cancer|tumor).*(sugar|azucar|glucose|fructose)/i.test(claim),
    institutions: [],
    consensus_statement: 'No established direct causal relationship between sugar and cancer per IARC/WHO. Indirect pathway via obesity exists. Direct causation claims are NOT supported by institutional consensus.',
    consensus_level: 'WEAK'
  },
  vaccine_safety: {
