const detectedConsensus = Object.entries(INSTITUTIONAL_CONSENSUS_DOMAINS)
  .filter(([, d]) => d.matches)
  .map(([key, d]) => ({
    domain: key,
    institutions: d.institutions,
    consensus_statement: d.consensus_statement,
    consensus_level: d.consensus_level
  }));

const hasInstitutionalConsensus = detectedConsensus.length > 0;

const levelOrder = ['VERY_STRONG', 'STRONG', 'MODERATE', 'WEAK', 'UNKNOWN'];
const institutionalConsensusStrength = detectedConsensus.length > 0
  ? detectedConsensus.reduce((best, d) =>
      levelOrder.indexOf(d.consensus_level) < levelOrder.indexOf(best)
        ? d.consensus_level : best
    , 'WEAK')
  : null;

// Instrucción para Gemini sobre consenso institucional
let institutional_consensus_instruction = '';
if (hasInstitutionalConsensus) {
  const strong = detectedConsensus.filter(d =>
    ['VERY_STRONG', 'STRONG'].includes(d.consensus_level));
  const weak = detectedConsensus.filter(d =>
    ['WEAK', 'UNKNOWN'].includes(d.consensus_level));

  if (strong.length > 0) {
    const domains = strong.map(d =>
      `${d.domain} [${d.institutions.join('/')}]: ${d.consensus_statement}`
    ).join(' | ');
    institutional_consensus_instruction =
      `INSTITUTIONAL CONSENSUS DETECTED (${institutionalConsensusStrength}): ${domains}. ` +
      `This consensus is independent of the retrieved articles. ` +
      `Even if articles are inconclusive or tangential, this institutional consensus should be considered as high-priority background context, but the final verdict must still depend on claim wording, scope, and retrieved evidence.`;
  }

  if (weak.length > 0) {
    const domains = weak.map(d =>
      `${d.domain}: ${d.consensus_statement}`
    ).join(' | ');
    institutional_consensus_instruction +=
      ` WEAK/NO CONSENSUS NOTE: ${domains}.`;
  }
}

