function getValidPhoneNumber(phone) {
  // Valores inválidos conocidos
  const invalidValues = ['unknown', '', null, undefined, '=', '#', 'default', 'undefined', 'null', '0', '-1'];

  const phoneStr = String(phone || '').trim();

  // Si está en la lista de inválidos
  if (invalidValues.includes(phoneStr)) {
    return null;
  }

  // Si no tiene al menos 8 dígitos (mínimo razonable para un teléfono)
  if (phoneStr.replace(/\D/g, '').length < 8) {
    return null;
  }

  // Limpiar: quitar espacios, guiones, etc.
  return phoneStr.replace(/\s/g, '').replace(/-/g, '');
}

// Obtener el teléfono de origen
let rawPhone = 
  body.from ||
  body.entry?.[0]?.changes?.[0]?.value?.contacts?.[0]?.wa_id ||
  null;

// Validar o usar DEFAULT
let validPhone = getValidPhoneNumber(rawPhone);

// Si no hay teléfono válido, usar el del .env
if (!validPhone) {
  validPhone = $env.DEFAULT_WHATSAPP_TO;

  // Si tampoco hay DEFAULT, usar 'unknown'
  if (!validPhone) {
    validPhone = 'unknown';
  }
}

return [{
  json: {
    original_claim: claim,
    claim_limpio: claimLimpio,
