  'protector solar': 'sunscreen',
  'crema solar': 'sunscreen',
  'fotoproteccion': 'photoprotection',
  'rayos uv': 'ultraviolet radiation',
  'radiacion ultravioleta': 'ultraviolet radiation',
  'uv': 'ultraviolet radiation',
  'uva': 'ultraviolet A',
  'uvb': 'ultraviolet B',
  'melanoma': 'melanoma',
  'cancer de piel': 'skin cancer',
  'cancer cutaneo': 'skin cancer',
  'carcinoma basocelular': 'basal cell carcinoma',
  'carcinoma espinocelular': 'squamous cell carcinoma',
  'carcinoma': 'carcinoma',
  'quemadura solar': 'sunburn',
  'quemaduras solares': 'sunburn',
  'bronceado': 'tanning',
  'cabinas solares': 'indoor tanning',
  'solarium': 'indoor tanning',
  'broncearse': 'tanning',
  'tomar sol': 'sun exposure',
  'callo solar': 'tanning',
  'adaptar la piel': 'skin adaptation',
  'piel adaptada': 'adapted skin',

  'cancer': 'cancer',
  'tumor': 'tumor',
  'dolor': 'pain',
  'ansiedad': 'anxiety',
  'depresion': 'depression',
  'sueno': 'sleep',
  'insomnio': 'insomnia',
  'vacunas': 'vaccines',
  'vacuna': 'vaccine'
};

// ============================================
// EXTRAER KEYWORDS
// ============================================

let keywords = [];

const terminosOrdenados = Object.entries(terminosMedicos)
  .sort((a, b) => b[0].length - a[0].length);

for (const [es, en] of terminosOrdenados) {
  if (claimLimpio.includes(es)) {
    keywords.push(en);
  }
}

const palabras = claimLimpio
  .split(' ')
  .filter(p =>
    p.length > 3 &&
    !stopWords.includes(p) &&
    !/^\d+$/.test(p)
  );

const palabrasTraducidas = palabras
  .filter(p => !keywords.includes(p))
  .filter(p => /^[a-zA-Z]+$/.test(p));

keywords.push(...palabrasTraducidas.slice(0, 3));

const bannedSpanish = [
  'reducir', 'aumenta', 'riesgo', 'muerte', 'buena', 'salud',
  'malo', 'mala', 'causa', 'provoca', 'produce',
  'radiacion', 'piel', 'cancer'
];

keywords = [...new Set(keywords)]
  .filter(Boolean)
  .filter(k => !bannedSpanish.includes(String(k).toLowerCase()))
  .filter(k => !/[áéíóúñ]/i.test(k))
  .filter(k => String(k).length > 2);

// Priorizar términos biomédicos fuertes
const priorityTerms = [
  'ultraviolet radiation',
  'sun exposure',
  'skin cancer',
  'melanoma',
  'basal cell carcinoma',
  'squamous cell carcinoma',
  'cancer',
  'mortality',
  'cardiovascular',
  'diabetes',
  'sugar',
  'sodium',
  'vitamin D',
  'omega-3',
  'creatine'
];

keywords.sort((a, b) => {
  const ai = priorityTerms.indexOf(a);
  const bi = priorityTerms.indexOf(b);

  const ap = ai === -1 ? 999 : ai;
  const bp = bi === -1 ? 999 : bi;

  return ap - bp;
});

if (keywords.length === 0) {
  keywords = claimLimpio
    .split(' ')
    .filter(p => p.length > 3 && !stopWords.includes(p))
    .slice(0, 6);
}

// ============================================
// DETECTAR TIPO DE CLAIM
// ============================================

let claim_type = 'GENERAL';

if (/(adelgazar|peso|obesidad|metabolismo|dieta|alimentacion|nutricion|azucar|sal|sodio|proteina|grasa|fibra|cafe|fructosa|glucosa)/.test(claimLimpio)) {
  claim_type = 'NUTRICION';
} else if (/(suplemento|vitamina|magnesio|creatina|omega|curcuma|ashwagandha|probiotico)/.test(claimLimpio)) {
  claim_type = 'SUPLEMENTO';
} else if (/(medicamento|farmaco|pastilla|tratamiento|dosis|ibuprofeno|paracetamol|antibiotico)/.test(claimLimpio)) {
  claim_type = 'MEDICAMENTO';
} else if (/(cancer|melanoma|piel|solar|sol|uv|diabetes|hipertension|depresion|ansiedad|tiroides|embarazo|higado|cardiovascular)/.test(claimLimpio)) {
  claim_type = 'CLINICO';
}

if (/(vitamina d|deficit vitamina d|deficiencia vitamina d)/.test(claimLimpio) && /(sol|solar|uv|piel|melanoma|protector)/.test(claimLimpio)) {
  claim_type = 'CLINICO_NUTRICION';
}

// ============================================
// DETECTAR PROBLEMA PRELIMINAR
// ============================================

const palabrasAbsolutas = [
  'siempre', 'nunca', 'todo', 'todos', 'ninguno', 'nadie',
  'absolutamente', 'completamente', 'garantizado', 'demostrado',
  'cura', 'elimina', 'evita', 'prohibido', 'toxica', 'toxico'
];

const palabrasCautela = [
  'puede', 'podria', 'tal vez', 'quizas', 'algunos',
  'frecuentemente', 'podria ayudar', 'asociado', 'parece'
];

const palabrasCausalidad = [
  'causa', 'provoca', 'produce', 'hace que', 'genera',
  'evita', 'cura', 'elimina', 'aumenta', 'reduce'
];

const tieneAbsoluto = palabrasAbsolutas.some(p => claimLimpio.includes(p));
const tieneCautela = palabrasCautela.some(p => claimLimpio.includes(p));
const tieneCausalidad = palabrasCausalidad.some(p => claimLimpio.includes(p));

let claim_problem_preliminar = 'NINGUNO';

if (tieneAbsoluto && !tieneCautela) {
  claim_problem_preliminar = 'ABSOLUTO_O_EXAGERADO';
} else if (tieneCausalidad) {
  claim_problem_preliminar = 'CAUSALIDAD_A_VERIFICAR';
} else if (keywords.length < 2) {
  claim_problem_preliminar = 'AMBIGUO';
}

if (/(sol|solar|uv|melanoma|protector solar|crema solar|fotoproteccion|vitamina d)/.test(claimLimpio)) {
  if (claim_problem_preliminar === 'NINGUNO') {
    claim_problem_preliminar = 'REQUIERE_BALANCE_RIESGO_BENEFICIO';
  }
}

// ============================================
// NOTA DE SESGO
// ============================================

let sesgo_nota = '';

if (tieneAbsoluto && !tieneCautela) {
  sesgo_nota = 'El claim usa lenguaje absoluto o fuerte. Requiere especial cautela metodológica.';
} else if (tieneCausalidad) {
  sesgo_nota = 'El claim plantea causalidad. Diferenciar asociación, mecanismo y causalidad clínica.';
} else if (/(sol|solar|uv|melanoma|protector solar|crema solar|fotoproteccion|vitamina d)/.test(claimLimpio)) {
  sesgo_nota = 'El claim requiere balance riesgo-beneficio: vitamina D, exposición UV, fotoprotección y riesgo de cáncer de piel.';
} else if (tieneCautela) {
  sesgo_nota = 'El claim usa lenguaje cauto. Evaluar si la evidencia respalda el matiz.';
} else {
  sesgo_nota = 'El claim será evaluado considerando contexto, población, dosis y calidad de evidencia.';
}

// ============================================
// OUTPUT
// ============================================

return [{
  json: {
    ...input,
    claim_type,
    claim_problem_preliminar,
    keywords_extraidas: keywords,
    sesgo_nota,
    tiene_absoluto: tieneAbsoluto,
    tiene_causalidad: tieneCausalidad,
    tiene_cura: /(cura|curar|curan|curen|cure)/i.test(originalClaim)
  }
}];

const input = $input.first().json;

const claimLimpio = String(input.claim_limpio || '').toLowerCase();
const claimType = input.claim_type || 'GENERAL';
const tieneCausalidad = input.tiene_causalidad || false;
const keywords = input.keywords_extraidas || [];

let estudioFiltro = '';

if (/(melanoma|cancer de piel|skin cancer|solar|uv|protector solar|fotoproteccion|vitamina d)/.test(claimLimpio)) {
  estudioFiltro = '(systematic review OR meta-analysis OR cohort study OR prospective study OR case-control study)';
} else if (claimType === 'MEDICAMENTO' || claimLimpio.includes('tratamiento') || claimLimpio.includes('intervencion')) {
  estudioFiltro = '(clinical trial OR randomized controlled trial OR systematic review OR meta-analysis)';
} else if (claimType === 'SUPLEMENTO') {
  estudioFiltro = '(clinical trial OR randomized controlled trial OR systematic review OR meta-analysis)';
} else if (tieneCausalidad || claimLimpio.includes('riesgo') || claimLimpio.includes('mortalidad')) {
  estudioFiltro = '(systematic review OR meta-analysis OR cohort study OR prospective study OR case-control study)';
} else {
  estudioFiltro = '(systematic review OR meta-analysis OR clinical trial OR cohort study)';
}

const keywordsFallback = keywords
  .filter(k => /^[a-zA-Z\s\-]+$/.test(k))
  .slice(0, 5);

let search_query_fallback = '';

if (keywordsFallback.length >= 2) {
  search_query_fallback = `(${keywordsFallback[0]}) AND (${keywordsFallback[1]}) AND ${estudioFiltro}`;
} else if (keywordsFallback.length === 1) {
  search_query_fallback = `(${keywordsFallback[0]}) AND ${estudioFiltro}`;
} else {
  search_query_fallback = `(health risk) AND ${estudioFiltro}`;
}

const retrieval_seeds = {
  primary_terms: keywordsFallback,
  study_filter: estudioFiltro,
  fallback_query: search_query_fallback,
  query_strategy:
    tieneCausalidad
      ? 'CAUSAL_OR_RISK_QUERY'
      : claimType === 'SUPLEMENTO' || claimType === 'MEDICAMENTO'
        ? 'INTERVENTION_QUERY'
        : 'GENERAL_EVIDENCE_QUERY'
};

return [{
  json: {
    ...input,
    estudioFiltro,
    search_query_fallback,
    retrieval_seeds
  }
}];

const input = $input.first().json;

const claim = String(input.original_claim || input.claim || '').trim();

const prompt = `Eres un experto en análisis de afirmaciones médicas y nutricionales. Tu tarea es descomponer el siguiente claim en sus componentes clave para una búsqueda bibliográfica en PubMed.

Claim: "${claim}"

Devuelve SOLO un JSON válido con esta estructura exacta:

{
  "exposure": "string (la sustancia, intervención, alimento, suplemento o exposición principal)",
  "exposure_terms": ["array de términos MeSH/sinónimos en inglés para la búsqueda"],
  "exposure_type": "supplement|medication|nutrition|environmental|lifestyle|other",
  "outcome": "string (el efecto, enfermedad o resultado que se afirma)",
  "outcome_terms": ["array de términos MeSH/sinónimos en inglés para la búsqueda"],
  "outcome_type": "disease|clinical_outcome|biomarker|symptom|mortality|quality_of_life|other",
  "direction": "beneficial|harmful|neutral|unclear",
  "relationship": "causal|association|prevention|treatment|no_relationship",
  "strength": "absolute|strong|cautious|neutral",
  "population": "string (población específica si se menciona, sino 'general population')",
  "study_design_hint": "RCT|cohort|case_control|systematic_review|meta_analysis|any"
}

REGLAS:
- exposure_terms y outcome_terms deben estar en INGLÉS y usar términos MeSH cuando sea posible
- Si el claim usa "cura", direction debe ser "beneficial"
- Si el claim usa "daña", direction debe ser "harmful"
- Si el claim usa "previene", direction debe ser "beneficial", relationship "prevention"
- Para dudas, usa valores por defecto razonables
- NO incluyas texto adicional fuera del JSON`;

let decomposition = {};

try {
  const geminiResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-lite:generateContent?key=${$env.GEMINI_API_KEY}`,
    headers: {
      'Content-Type': 'application/json'
    },
    body: {
      contents: [
        {
          role: 'user',
          parts: [{ text: prompt }]
        }
      ],
      generationConfig: {
        temperature: 0.1,
        maxOutputTokens: 800,
        responseMimeType: 'application/json'
      }
    },
    json: true
  });

  const responseText =
    geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';

  const clean = responseText
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  decomposition = JSON.parse(clean);

} catch (e) {
  console.error('Error calling/parsing Gemini:', e);

  decomposition = {
    exposure: 'unknown',
    exposure_terms: [],
    exposure_type: 'other',
    outcome: 'health outcome',
    outcome_terms: [],
    outcome_type: 'other',
    direction: 'unclear',
    relationship: 'association',
    strength: 'neutral',
    population: 'general population',
    study_design_hint: 'any'
  };
}

return [{
  json: {
    ...input,
    claim_decomposition: decomposition
  }
}];

const input = $input.first().json;

return [{
  json: {
    ...input,
    queryGeminiBody: {
      contents: [
        {
          role: "user",
          parts: [
            {
              text: String(input.geminiQueryPrompt || "Generate a PubMed query about sodium intake and mortality")
            }
          ]
        }
      ],
      generationConfig: {
        temperature: 0.1,
        maxOutputTokens: 300
      }
    }
  }
}];

return [{
  json: {
    ...$json,

    status: "completed",

    result: {
      verdict: $json.language === "en"
        ? "INSUFFICIENT_EVIDENCE"
        : "EVIDENCIA_INSUFICIENTE",

      confidence: "LOW",

      consensus: $json.language === "en"
        ? "INSUFFICIENT"
        : "INSUFICIENTE",

      summary: $json.language === "en"
        ? "No relevant scientific evidence was found in PubMed for this claim."
        : "No se encontraron evidencias científicas relevantes en PubMed para esta afirmación.",

      detailed_analysis: $json.language === "en"
        ? "The literature search did not identify relevant articles suitable for evidence assessment."
        : "La búsqueda bibliográfica no identificó artículos relevantes para realizar una evaluación de la evidencia.",

      articles_analyzed: 0,

      references: []
    }
  }
}];
